import { Link, useLocation } from "wouter";
import {
  Sidebar,
  SidebarContent,
  SidebarGroup,
  SidebarGroupContent,
  SidebarGroupLabel,
  SidebarMenu,
  SidebarMenuButton,
  SidebarMenuItem,
  SidebarHeader,
  SidebarFooter,
  useSidebar,
} from "@/components/ui/sidebar";
import {
  LayoutDashboard,
  User,
  Link as LinkIcon,
  Store,
  Code,
  History,
  Settings,
  Megaphone,
  FileText,
  HelpCircle,
  LogOut,
  TrendingUp,
  Shield,
  Globe,
} from "lucide-react";
import { useQuery } from "@tanstack/react-query";
import type { User as UserType } from "@shared/schema";
import logoImage from "@assets/bkapay-logo.png";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { useMutation } from "@tanstack/react-query";
import { apiRequest } from "@/lib/queryClient";
import { useToast } from "@/hooks/use-toast";

const menuItems = [
  {
    title: "Tableau de bord",
    url: "/dashboard",
    icon: LayoutDashboard,
    testId: "nav-dashboard",
  },
  {
    title: "Profil",
    url: "/dashboard/profile",
    icon: User,
    testId: "nav-profile",
  },
  {
    title: "Lien de paiement",
    url: "/dashboard/payment-links",
    icon: LinkIcon,
    testId: "nav-payment-links",
  },
  {
    title: "Lien marchand",
    url: "/dashboard/merchant-links",
    icon: Store,
    testId: "nav-merchant-links",
  },
  {
    title: "API",
    url: "/dashboard/api",
    icon: Code,
    testId: "nav-api",
  },
  {
    title: "Analytics",
    url: "/dashboard/analytics",
    icon: TrendingUp,
    testId: "nav-analytics",
  },
  {
    title: "Verification KYC",
    url: "/dashboard/kyc",
    icon: Shield,
    testId: "nav-kyc",
  },
  {
    title: "Historique",
    url: "/dashboard/history",
    icon: History,
    testId: "nav-history",
  },
  {
    title: "Paramètres",
    url: "/dashboard/settings",
    icon: Settings,
    testId: "nav-settings",
  },
  {
    title: "Documentation",
    url: "/dashboard/documentation",
    icon: FileText,
    testId: "nav-documentation",
  },
  {
    title: "Support",
    url: "/dashboard/support",
    icon: HelpCircle,
    testId: "nav-support",
  },
];

export function AppSidebar() {
  const [location, setLocation] = useLocation();
  const { toast } = useToast();
  const { setOpenMobile, isMobile } = useSidebar();

  const { data: user } = useQuery<UserType>({
    queryKey: ["/api/auth/me"],
  });


  const handleMenuClick = () => {
    if (isMobile) {
      setOpenMobile(false);
    }
  };

  // Ajouter items Admin si l'utilisateur est admin
  const sidebarMenuItems = [...menuItems];
  if (user?.isAdmin) {
    sidebarMenuItems.push({
      title: "Administration",
      url: "/dashboard/admin",
      icon: Shield,
      testId: "nav-admin",
    });
  }

  const logoutMutation = useMutation({
    mutationFn: async () => {
      await apiRequest("POST", "/api/auth/logout", {});
    },
    onSuccess: () => {
      localStorage.removeItem("adminAccessCode");
      toast({
        title: "Déconnexion réussie",
        description: "À bientôt sur BKApay",
      });
      setLocation("/");
    },
    onError: () => {
      toast({
        title: "Erreur",
        description: "Erreur lors de la déconnexion",
        variant: "destructive",
      });
    },
  });

  const handleLogout = () => {
    logoutMutation.mutate();
  };

  return (
    <Sidebar>
      <SidebarHeader className="p-6">
        <div className="flex items-center gap-3">
          <img src={logoImage} alt="BKApay" className="h-10 w-auto" />
        </div>
      </SidebarHeader>
      <SidebarContent>
        <SidebarGroup>
          <SidebarGroupLabel>Menu</SidebarGroupLabel>
          <SidebarGroupContent>
            <SidebarMenu>
              {sidebarMenuItems.map((item) => (
                <SidebarMenuItem key={item.title}>
                  <SidebarMenuButton
                    asChild
                    isActive={location === item.url}
                    data-testid={item.testId}
                  >
                    <Link href={item.url} onClick={handleMenuClick}>
                      <item.icon className="w-4 h-4" />
                      <span>{item.title}</span>
                    </Link>
                  </SidebarMenuButton>
                </SidebarMenuItem>
              ))}
            </SidebarMenu>
          </SidebarGroupContent>
        </SidebarGroup>
      </SidebarContent>
      <SidebarFooter className="p-4">
        <Button
          variant="ghost"
