  DialogHeader,
  DialogTitle,
  DialogTrigger,
} from "@/components/ui/dialog";
import { useForm } from "react-hook-form";
import { zodResolver } from "@hookform/resolvers/zod";
import { z } from "zod";
import { Form, FormControl, FormField, FormItem, FormLabel, FormMessage } from "@/components/ui/form";

// Compress image with high quality
const compressImage = (file: File): Promise<string> => {
  return new Promise((resolve, reject) => {
    const reader = new FileReader();
    reader.readAsDataURL(file);
    reader.onload = (event) => {
      const img = new Image();
      img.src = event.target?.result as string;
      img.onload = () => {
        const canvas = document.createElement("canvas");
        let width = img.width;
        let height = img.height;

        // Reduce to max 1200x1200 for good quality
        if (width > 1200 || height > 1200) {
          const ratio = Math.min(1200 / width, 1200 / height);
          width = Math.round(width * ratio);
          height = Math.round(height * ratio);
        }

        canvas.width = width;
        canvas.height = height;
        const ctx = canvas.getContext("2d");
        if (!ctx) {
          reject(new Error("Cannot get canvas context"));
          return;
        }
        ctx.imageSmoothingEnabled = true;
        ctx.imageSmoothingQuality = "high";
        ctx.drawImage(img, 0, 0, width, height);
        resolve(canvas.toDataURL("image/jpeg", 0.92));
      };
      img.onerror = () => reject(new Error("Cannot load image"));
    };
    reader.onerror = () => reject(new Error("Cannot read file"));
  });
};

const paymentLinkSchema = z.object({
  productName: z.string().min(1, "Le nom du produit est requis"),
  description: z.string().optional(),
  amount: z.preprocess(
    (val) => {
      if (val === "" || val === undefined || val === null) return undefined;
      const num = Number(val);
      return isNaN(num) ? undefined : num;
    },
    z.number({ invalid_type_error: "Veuillez entrer un montant valide" }).min(1, "Veuillez saisir un montant valide")
  ),
  allowedCountries: z.array(z.string()).default([]),
  customerPaysFee: z.boolean().default(false),
  customerPaysCryptoFee: z.boolean().default(false),
});

type PaymentLinkFormData = z.infer<typeof paymentLinkSchema>;

export default function PaymentLinks() {
  const [dialogOpen, setDialogOpen] = useState(false);
  const [editingId, setEditingId] = useState<string | null>(null);
  const [imagePreviews, setImagePreviews] = useState<string[]>([]);
  const [existingImages, setExistingImages] = useState<string[]>([]);
  const [newImageFiles, setNewImageFiles] = useState<File[]>([]);
  const [videoUrl, setVideoUrl] = useState<string | null>(null);
  const [successToken, setSuccessToken] = useState<string | null>(null);
  const [successImage, setSuccessImage] = useState<string | null>(null);
  const [amountInput, setAmountInput] = useState<string>("");
  const [selectedCurrency, setSelectedCurrency] = useState<string>("XOF");
  const { toast } = useToast();

  const { data: paymentLinks, isLoading } = useQuery<(PaymentLink & { hasImages?: boolean; hasVideo?: boolean })[]>({
    queryKey: ["/api/payment-links", "light"],
    queryFn: async () => {
      const res = await fetch("/api/payment-links?light=true", { credentials: "include" });
      if (!res.ok) throw new Error("Erreur");
      return res.json();
    },
  });

  const { data: user } = useQuery<User>({
    queryKey: ["/api/auth/me"],
  });

  const userCountry = user?.country || "";
  const userBalanceCurrency = userCountry 
    ? COUNTRIES.find(c => c.code === userCountry)?.currency || "XOF"
    : "XOF";

  const { paymentLinkMin } = useConvertedMinimums(userBalanceCurrency);

  useEffect(() => {
    if (userBalanceCurrency) {
      setSelectedCurrency(userBalanceCurrency);
    }
  }, [userBalanceCurrency]);

  // Fetch enabled countries for deposits (incoming payments)
  const { data: enabledCountriesOperators } = useQuery<Record<string, string[]>>({
    queryKey: ["/api/countries-operators/deposits"],
  });

  // Filter countries to only show those enabled by admin
  const COLLECT_COUNTRIES = enabledCountriesOperators 
    ? COUNTRIES.filter(c => Object.keys(enabledCountriesOperators).includes(c.code))
    : [];

  const form = useForm<PaymentLinkFormData>({
    resolver: zodResolver(paymentLinkSchema),
    defaultValues: {
      productName: "",
      description: "",
      amount: undefined as any,
      allowedCountries: [],
      customerPaysFee: false,
      customerPaysCryptoFee: false,
    },
  });

  const startEditingLink = async (link: PaymentLink) => {
    setEditingId(link.id);
    setAmountInput(String(link.amount));
    form.reset({
      productName: link.productName,
      description: link.description || "",
      amount: link.amount,
      allowedCountries: link.allowedCountries || [],
      customerPaysFee: link.customerPaysFee || false,
      customerPaysCryptoFee: (link as any).customerPaysCryptoFee || false,
    });
    setImagePreviews([]);
    setNewImageFiles([]);
    setDialogOpen(true);

    try {
      const res = await fetch(`/api/payment-links/${link.id}`, { credentials: "include" });
      if (res.ok) {
        const fullLink: PaymentLink = await res.json();
        const images = fullLink.imageUrls?.length ? fullLink.imageUrls : (fullLink.imageUrl ? [fullLink.imageUrl] : []);
        setExistingImages(images);
        setVideoUrl(fullLink.videoUrl || null);
      } else {
        setExistingImages([]);
        setVideoUrl(null);
      }
    } catch {
      setExistingImages([]);
      setVideoUrl(null);
    }
  };

  const handleImageAdd = async (files: FileList | null) => {
    if (!files) return;
    const totalImages = existingImages.length + imagePreviews.length;
    const remaining = 3 - totalImages;
    if (remaining <= 0) {
      toast({ title: "Maximum 3 images", description: "Vous ne pouvez pas ajouter plus de 3 images", variant: "destructive" });
      return;
    }
    const filesToAdd = Array.from(files).slice(0, remaining);
    const newPreviews: string[] = [];
    const newFiles: File[] = [];
    for (const file of filesToAdd) {
      try {
        const compressed = await compressImage(file);
        newPreviews.push(compressed);
        newFiles.push(file);
      } catch {
        toast({ title: "Erreur", description: "Erreur lors du traitement d'une image", variant: "destructive" });
      }
    }
    setImagePreviews(prev => [...prev, ...newPreviews]);
    setNewImageFiles(prev => [...prev, ...newFiles]);
  };

  const removeExistingImage = (index: number) => {
    setExistingImages(prev => prev.filter((_, i) => i !== index));
  };

  const removeNewImage = (index: number) => {
    setImagePreviews(prev => prev.filter((_, i) => i !== index));
    setNewImageFiles(prev => prev.filter((_, i) => i !== index));
  };

  const createMutation = useMutation({
    mutationFn: async (data: PaymentLinkFormData) => {
      const allImages = [...imagePreviews];

      const res = await apiRequest("POST", "/api/payment-links", {
        productName: data.productName,
        description: data.description,
        amount: data.amount,
        imageUrls: allImages,
        videoUrl: videoUrl,
        allowedCountries: data.allowedCountries,
        customerPaysFee: data.customerPaysFee,
        customerPaysCryptoFee: data.customerPaysCryptoFee,
      });
      return res.json() as Promise<PaymentLink>;
    },
    onSuccess: (data: PaymentLink) => {
      queryClient.invalidateQueries({ queryKey: ["/api/payment-links"] });
      if (data.imageUrls?.[0] || data.imageUrl) {
        setSuccessImage(data.imageUrls?.[0] || data.imageUrl || null);
      }
      setSuccessToken(data.token);
      setDialogOpen(false);
      setImagePreviews([]);
      setNewImageFiles([]);
      setExistingImages([]);
      setVideoUrl(null);
      form.reset();
    },
    onError: (error: any) => {
      toast({
        title: "Erreur",
        description: error.message || "Erreur lors de la création du lien",
        variant: "destructive",
      });
    },
  });

  const editMutation = useMutation({
    mutationFn: async (data: PaymentLinkFormData) => {
      const allImages = [...existingImages, ...imagePreviews];

      const res = await apiRequest("PATCH", `/api/payment-links/${editingId}`, {
        productName: data.productName,
        description: data.description,
        amount: data.amount,
        imageUrls: allImages,
        videoUrl: videoUrl,
        allowedCountries: data.allowedCountries,
        customerPaysFee: data.customerPaysFee,
        customerPaysCryptoFee: data.customerPaysCryptoFee,
      });
      return res.json() as Promise<PaymentLink>;
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/payment-links"] });
      toast({
        title: "Lien modifié",
        description: "Le lien de paiement a été modifié avec succès",
      });
      setEditingId(null);
      setDialogOpen(false);
      setImagePreviews([]);
      setNewImageFiles([]);
      setExistingImages([]);
      setVideoUrl(null);
      form.reset();
    },
    onError: (error: any) => {
      toast({
        title: "Erreur",
        description: error.message || "Erreur lors de la modification",
        variant: "destructive",
      });
    },
  });

  const deleteMutation = useMutation({
    mutationFn: async (id: string) => {
      return await apiRequest("DELETE", `/api/payment-links/${id}`, {});
    },
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ["/api/payment-links"] });
      toast({
        title: "Lien supprimé",
        description: "Le lien de paiement a été supprimé",
      });
    },
    onError: (error: any) => {
      toast({
        title: "Erreur",
        description: error.message || "Erreur lors de la suppression",
        variant: "destructive",
      });
    },
  });

  const copyToClipboard = (token: string, isShortToken = false) => {
    const textToCopy = isShortToken ? token : `${window.location.origin}/pay/${token}`;
    navigator.clipboard.writeText(textToCopy);
    toast({
      title: "Copié",
      description: isShortToken ? "Le token a été copié" : "Le lien a été copié dans le presse-papiers",
    });
  };

  const closeSuccess = () => {
    setSuccessImage(null);
    setSuccessToken(null);
  };

  const onSubmit = (data: PaymentLinkFormData) => {
    if (editingId) {
      editMutation.mutate(data);
    } else {
      createMutation.mutate(data);
    }
  };

  // Success screen overlay - show ONLY image and short link
  if (successToken) {
    return (
      <div className="fixed inset-0 bg-black/50 flex items-center justify-center p-4">
        <Card className="w-full max-w-sm">
          <CardContent className="pt-6 flex flex-col items-center text-center space-y-4">
            {successImage && (
              <img
                src={successImage}
                alt="Produit"
                className="max-h-56 w-auto rounded-md"
              />
            )}
            <div className="bg-muted rounded-md p-3 flex items-center justify-between gap-2 w-full">
              <code className="text-xs sm:text-sm font-mono text-foreground flex-1 text-center">
                {successToken}
              </code>
              <Button
                size="sm"
                variant="ghost"
                onClick={() => copyToClipboard(successToken, true)}
                className="flex-shrink-0"
                data-testid="button-copy-success"
              >
                <Copy className="w-4 h-4" />
              </Button>
            </div>
            <Button
              onClick={closeSuccess}
              className="w-full"
              data-testid="button-done"
            >
              Continuer
            </Button>
          </CardContent>
        </Card>
      </div>
    );
  }

  return (
    <div className="flex flex-col h-full">
      <div className="flex items-center justify-between gap-2 flex-wrap mb-4">
        <div>
          <h1 className="text-2xl font-bold text-foreground mb-1">Liens de paiement</h1>
          <p className="text-sm text-muted-foreground">
            Montant fixe - partagez vos liens
          </p>
        </div>
        <Dialog open={dialogOpen} onOpenChange={(open) => {
          if (open && !editingId) {
            form.reset({
              productName: "",
              description: "",
              amount: undefined as any,
              allowedCountries: [],
              customerPaysFee: false,
              customerPaysCryptoFee: false,
            });
            setAmountInput("");
            setExistingImages([]);
            setImagePreviews([]);
            setNewImageFiles([]);
            setVideoUrl(null);
          }
          setDialogOpen(open);
        }}>
          <DialogTrigger asChild>
            <Button data-testid="button-create-link" onClick={() => setEditingId(null)}>
              <Plus className="w-4 h-4 mr-2" />
              Nouveau lien
            </Button>
          </DialogTrigger>
          <DialogContent className="max-w-2xl max-h-[90vh] overflow-y-auto">
            <DialogHeader>
              <DialogTitle>{editingId ? "Modifier le lien de paiement" : "Créer un lien de paiement"}</DialogTitle>
              <DialogDescription>
                {editingId ? "Modifiez les informations de votre produit ou service" : "Remplissez les informations de votre produit ou service"}
              </DialogDescription>
            </DialogHeader>
            <Form {...form}>
              <form onSubmit={form.handleSubmit(onSubmit)} className="space-y-4 pb-4">
                <FormField
                  control={form.control}
                  name="productName"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Nom du produit</FormLabel>
                      <FormControl>
                        <Input
                          placeholder="Ex: Formation en ligne"
                          data-testid="input-product-name"
                          {...field}
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="description"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Description (optionnel)</FormLabel>
                      <FormControl>
                        <Textarea
                          placeholder="Décrivez votre produit..."
                          rows={3}
                          data-testid="input-description"
                          {...field}
                        />
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                <FormField
                  control={form.control}
                  name="amount"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel>Montant ({selectedCurrency})</FormLabel>
                      <FormControl>
                        <Input
                          type="text"
                          inputMode="numeric"
                          placeholder="10000"
                          data-testid="input-amount"
                          value={amountInput}
                          onChange={(e) => {
                            const val = e.target.value.replace(/[^0-9]/g, "");
                            setAmountInput(val);
                            if (val === "") {
                              field.onChange(undefined);
                            } else {
                              field.onChange(Number(val));
                            }
                          }}
                        />
                      </FormControl>
                      <p className="text-xs text-muted-foreground mt-1">Montant minimum: {paymentLinkMin.toLocaleString("fr-FR")} {selectedCurrency}</p>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                {userBalanceCurrency && (
                  <div className="text-sm text-muted-foreground">
                    Devise : <span className="font-medium text-foreground">{userBalanceCurrency}</span>
                  </div>
                )}

                {/* Section Photos - désactivée si vidéo existe */}
                <div className={`space-y-4 border rounded-lg p-4 ${videoUrl ? 'bg-muted/50 opacity-60' : 'bg-muted/30'}`}>
                  <div className="flex items-center gap-2">
                    <ImageIcon className="w-5 h-5 text-primary" />
                    <Label className="text-base font-medium">Photos du produit</Label>
                    <span className="text-xs text-muted-foreground ml-auto">({existingImages.length + imagePreviews.length}/3)</span>
                  </div>

                  {videoUrl ? (
                    <p className="text-sm text-muted-foreground text-center py-4">
                      Vous avez déjà ajouté une vidéo. Supprimez la vidéo pour ajouter des photos.
                    </p>
                  ) : (
                    <>
                      <div className="flex flex-wrap gap-2">
                        {existingImages.map((img, index) => (
                          <div key={`existing-${index}`} className="relative w-20 h-20">
                            <img src={img} alt={`Image ${index + 1}`} className="w-full h-full object-cover rounded-md border" />
                            <Button
                              type="button"
                              size="icon"
                              variant="destructive"
                              className="absolute -top-2 -right-2 h-5 w-5"
                              onClick={() => removeExistingImage(index)}
                              data-testid={`btn-remove-existing-image-${index}`}
                            >
                              <Trash2 className="h-3 w-3" />
                            </Button>
                          </div>
                        ))}
                        {imagePreviews.map((img, index) => (
                          <div key={`new-${index}`} className="relative w-20 h-20">
                            <img src={img} alt={`Nouvelle ${index + 1}`} className="w-full h-full object-cover rounded-md border" />
                            <Button
                              type="button"
                              size="icon"
                              variant="destructive"
                              className="absolute -top-2 -right-2 h-5 w-5"
                              onClick={() => removeNewImage(index)}
                              data-testid={`btn-remove-new-image-${index}`}
                            >
                              <Trash2 className="h-3 w-3" />
                            </Button>
                          </div>
                        ))}
                      </div>

                      {existingImages.length + imagePreviews.length < 3 && (
                        <label className="w-full h-12 border-2 border-dashed rounded-md flex items-center justify-center gap-2 cursor-pointer hover:bg-muted/50">
                          <input
                            type="file"
                            accept="image/*"
                            multiple
                            className="hidden"
                            data-testid="input-image-files"
                            onChange={(e) => handleImageAdd(e.target.files)}
                          />
                          <Plus className="h-5 w-5 text-muted-foreground" />
                          <span className="text-sm text-muted-foreground">Ajouter des photos</span>
                        </label>
                      )}
                    </>
                  )}
                </div>

                {/* Section Vidéo - désactivée si photos existent */}
                <div className={`space-y-4 border rounded-lg p-4 ${(existingImages.length + imagePreviews.length) > 0 ? 'bg-muted/50 opacity-60' : 'bg-muted/30'}`}>
                  <div className="flex items-center gap-2">
                    <Video className="w-5 h-5 text-primary" />
                    <Label className="text-base font-medium">Vidéo du produit</Label>
                    <span className="text-xs text-muted-foreground ml-auto">(max 30s)</span>
                  </div>

                  {(existingImages.length + imagePreviews.length) > 0 ? (
                    <p className="text-sm text-muted-foreground text-center py-4">
                      Vous avez déjà ajouté des photos. Supprimez les photos pour ajouter une vidéo.
                    </p>
                  ) : (
                    <VideoUploader
                      videoUrl={videoUrl}
                      onVideoChange={setVideoUrl}
                      maxDuration={30}
                    />
                  )}
                </div>

                {/* Pays autorisés */}
                <FormField
                  control={form.control}
                  name="allowedCountries"
                  render={({ field }) => (
                    <FormItem>
                      <FormLabel className="flex items-center gap-2">
                        <Globe className="w-4 h-4" />
                        Pays autorisés
                      </FormLabel>
                      <FormControl>
                        <div className="space-y-2">
                          <p className="text-sm text-muted-foreground">
                            Sélectionnez les pays où les clients peuvent payer. Si aucun pays n'est sélectionné, tous les pays seront disponibles.
                          </p>
                          <div className="grid grid-cols-2 gap-2">
                            {COLLECT_COUNTRIES.map((country) => (
                              <div key={country.code} className="flex items-center space-x-2">
                                <Checkbox
                                  id={`country-${country.code}`}
                                  data-testid={`checkbox-country-${country.code}`}
                                  checked={field.value?.includes(country.code)}
                                  onCheckedChange={(checked) => {
                                    if (checked) {
                                      field.onChange([...(field.value || []), country.code]);
                                    } else {
                                      field.onChange(field.value?.filter((c: string) => c !== country.code) || []);
                                    }
                                  }}
                                />
                                <Label htmlFor={`country-${country.code}`} className="text-sm cursor-pointer flex items-center gap-1">
                                  <CountryFlag code={country.code} size="xs" />
                                  <span>{country.name}</span>
                                </Label>
                              </div>
                            ))}
                          </div>
                        </div>
                      </FormControl>
                      <FormMessage />
                    </FormItem>
                  )}
                />

                {/* Frais Mobile Money */}
                <FormField
                  control={form.control}
                  name="customerPaysFee"
                  render={({ field }) => (
                    <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4">
                      <div className="space-y-0.5">
                        <FormLabel className="flex items-center gap-2">
                          <Wallet className="w-4 h-4" />
                          Frais Mobile Money a la charge du client
                        </FormLabel>
                        <p className="text-sm text-muted-foreground">
                          Si active, le client paiera les frais de transaction Mobile Money en plus du montant.
                        </p>
                      </div>
                      <FormControl>
                        <Switch
                          data-testid="switch-customer-pays-fee"
                          checked={field.value}
                          onCheckedChange={field.onChange}
                        />
                      </FormControl>
                    </FormItem>
                  )}
                />

                {/* Frais Crypto */}
                <FormField
                  control={form.control}
                  name="customerPaysCryptoFee"
                  render={({ field }) => (
                    <FormItem className="flex flex-row items-center justify-between rounded-lg border p-4">
                      <div className="space-y-0.5">
                        <FormLabel className="flex items-center gap-2">
                          <Wallet className="w-4 h-4" />
                          Frais Crypto a la charge du client
                        </FormLabel>
                        <p className="text-sm text-muted-foreground">
                          Si active, le client paiera les frais de transaction crypto en plus du montant.
                        </p>
                      </div>
                      <FormControl>
                        <Switch
                          data-testid="switch-customer-pays-crypto-fee"
                          checked={field.value}
                          onCheckedChange={field.onChange}
                        />
                      </FormControl>
                    </FormItem>
                  )}
                />

                <div className="flex justify-end gap-3">
                  <Button
                    type="button"
                    variant="outline"
                    onClick={() => {
                      setDialogOpen(false);
                      setEditingId(null);
                      form.reset();
                    }}
                    data-testid="button-cancel"
                  >
                    Annuler
                  </Button>
                  <Button
                    type="submit"
                    disabled={editingId ? editMutation.isPending : createMutation.isPending}
                    data-testid="button-submit"
                  >
                    {editingId ? (
                      editMutation.isPending ? "Modification..." : "Modifier le lien"
                    ) : (
                      createMutation.isPending ? "Création..." : "Créer le lien"
                    )}
                  </Button>
                </div>
              </form>
            </Form>
          </DialogContent>
        </Dialog>
      </div>

      {/* Payment Links List - Scrollable Container */}
      <div className="flex-1 overflow-y-auto pr-3">
        <div className="grid gap-6">
          {isLoading ? (
            <Card>
              <CardContent className="py-12">
                <p className="text-center text-muted-foreground">Chargement...</p>
              </CardContent>
            </Card>
          ) : paymentLinks && paymentLinks.length > 0 ? (
            paymentLinks.map((link) => (
            <Card key={link.id} data-testid={`payment-link-${link.id}`}>
              <CardHeader>
                <div className="flex items-start justify-between gap-4 flex-wrap">
                  <div className="flex-1 min-w-0">
                    <div className="flex items-center gap-2 flex-wrap mb-2">
                      <CardTitle className="text-lg">{link.productName}</CardTitle>
                      <Badge variant={link.isActive ? "default" : "secondary"}>
                        {link.isActive ? "Actif" : "Inactif"}
                      </Badge>
                    </div>
                    {link.description && (
                      <p className="text-sm text-muted-foreground">{link.description}</p>
                    )}
                  </div>
                  <div className="text-right">
                    <p className="text-2xl font-bold">
                      {new Intl.NumberFormat("fr-FR").format(link.amount)} {userBalanceCurrency}
                    </p>
                  </div>
                </div>
              </CardHeader>
              <CardContent>
                <div className="space-y-4">
                  {((link as any).hasImages || (link as any).hasVideo) && (
                    <div className="flex items-center gap-2">
                      {(link as any).hasImages && (
                        <Badge variant="secondary">
                          <ImageIcon className="w-3 h-3 mr-1" />
                          Photos
                        </Badge>
                      )}
                      {(link as any).hasVideo && (
                        <Badge variant="secondary">
                          <Video className="w-3 h-3 mr-1" />
