  amount, 
  count, 
  total,
  index,
  currency = "XOF"
}: { 
  type: string; 
  amount: number; 
  count: number; 
  total: number;
  index: number;
  currency?: string;
}) {
  const Icon = TYPE_ICONS[type] || CreditCard;
  const percentage = total > 0 ? (amount / total) * 100 : 0;

  return (
    <motion.div
      variants={itemVariants}
      initial="hidden"
      animate="visible"
      transition={{ delay: index * 0.1 }}
