                              })}
                            </div>
                          ) : (
                            <span className="font-medium">Tous les pays</span>
                          )}
                        </div>
                        <div>
                          <span className="text-muted-foreground">Frais Mobile Money: </span>
                          <Badge variant={(apiKey as any).customerPaysFee ? "default" : "outline"} className="text-xs">
