                        <Button
                          size="sm"
                          variant="outline"
                          onClick={() => setUnsuspendDialog({ open: true, userId: user.id, userName: `${user.firstName} ${user.lastName}` })}
                          disabled={unsuspendUserMutation.isPending}
                          data-testid={`button-unsuspend-${user.id}`}
