// API Keys Dialog Component
export function ApiKeysDialog({ userId, onOpenChange }: { userId: string; onOpenChange: () => void }) {
  const { data: keys, isLoading } = useQuery<ApiKey[]>({
    queryKey: [`/api/admin/user/${userId}/api-keys`],
  });
  const [visibleKeys, setVisibleKeys] = useState<Record<string, boolean>>({});
  const { toast } = useToast();

  const maskKey = (key: string) => key.slice(0, 10) + "..." + key.slice(-4);

  const toggleKeyVisibility = (id: string) => {
    setVisibleKeys((prev) => ({ ...prev, [id]: !prev[id] }));
  };

  const copyToClipboard = (text: string, label: string) => {
    navigator.clipboard.writeText(text);
    toast({ title: "Copié", description: `${label} copié` });
  };

  return (
    <Dialog open={true} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-3xl max-h-[80vh]">
        <DialogHeader>
          <DialogTitle>Clés API</DialogTitle>
        </DialogHeader>
        {isLoading ? (
          <div className="space-y-3">
            {[1, 2, 3].map((i) => (
              <Skeleton key={i} className="h-40 w-full" />
            ))}
          </div>
        ) : keys && keys.length > 0 ? (
          <ScrollArea className="h-[400px]">
            <div className="space-y-4 pr-4">
              {keys.map((key) => (
                <Card key={key.id}>
                  <CardHeader>
                    <div className="flex items-center justify-between gap-2">
                      <CardTitle className="text-lg">{key.name}</CardTitle>
                      <Badge variant={key.isActive ? "default" : "secondary"}>
                        {key.isActive ? "Active" : "Inactive"}
                      </Badge>
                    </div>
                    <CardDescription>{new Date(key.createdAt).toLocaleDateString("fr-FR")}</CardDescription>
                  </CardHeader>
                  <CardContent className="space-y-3">
                    <div>
                      <label className="text-xs font-medium text-muted-foreground block mb-2">Clé publique (Frontend)</label>
                      <div className="flex gap-2 items-center">
                        <code className="flex-1 bg-muted p-2 rounded text-xs font-mono truncate">
                          {visibleKeys[key.id + "-public"] ? key.publicKey : maskKey(key.publicKey)}
                        </code>
                        <Button size="sm" variant="ghost" onClick={() => toggleKeyVisibility(key.id + "-public")}>
                          {visibleKeys[key.id + "-public"] ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                        </Button>
                        <Button size="sm" variant="ghost" onClick={() => copyToClipboard(key.publicKey, "Clé publique")}>
                          <Copy className="w-4 h-4" />
                        </Button>
                      </div>
                    </div>
                    <div>
                      <label className="text-xs font-medium text-muted-foreground block mb-2">Clé privée (Backend)</label>
                      <div className="flex gap-2 items-center">
                        <code className="flex-1 bg-muted p-2 rounded text-xs font-mono truncate">
                          {visibleKeys[key.id + "-private"] ? key.privateKey : maskKey(key.privateKey)}
                        </code>
                        <Button size="sm" variant="ghost" onClick={() => toggleKeyVisibility(key.id + "-private")}>
                          {visibleKeys[key.id + "-private"] ? <EyeOff className="w-4 h-4" /> : <Eye className="w-4 h-4" />}
                        </Button>
                        <Button size="sm" variant="ghost" onClick={() => copyToClipboard(key.privateKey, "Clé privée")}>
                          <Copy className="w-4 h-4" />
                        </Button>
                      </div>
                    </div>
                  </CardContent>
                </Card>
              ))}
            </div>
          </ScrollArea>
        ) : (
          <p className="text-center py-8 text-muted-foreground">Aucune clé API</p>
        )}
      </DialogContent>
    </Dialog>
  );
}

// Profile Dialog Component
export function ProfileDialog({ userId, onOpenChange }: { userId: string; onOpenChange: () => void }) {
  const { data: user, isLoading, refetch } = useQuery<User>({
    queryKey: [`/api/admin/user/${userId}/profile`],
  });
  const { toast } = useToast();
  const [toggling, setToggling] = React.useState(false);

  const profileCurrency = user?.country
    ? COUNTRIES.find(c => c.code === user.country)?.currency || "XOF"
    : "XOF";

  const formatAmount = (amount: number) => {
    return `${amount.toLocaleString("fr-FR")} ${profileCurrency}`;
  };

  const handleToggleVerification = async () => {
    if (!user) return;
    try {
      setToggling(true);
      const response = await fetch("/api/admin/toggle-verification", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({ userId }),
      });

      if (!response.ok) {
        const error = await response.json();
        throw new Error(error.error || "Erreur lors de la modification du statut de vérification");
      }

      toast({
        title: "Succès",
        description: user.kycStatus === "verified" ? "Compte dévérifié" : "Compte vérifié",
      });

      await refetch();
    } catch (error: any) {
      toast({
        title: "Erreur",
        description: error.message,
        variant: "destructive",
      });
    } finally {
      setToggling(false);
    }
  };

  return (
    <Dialog open={true} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-md">
        <DialogHeader>
          <DialogTitle>Profil utilisateur</DialogTitle>
        </DialogHeader>
        {isLoading ? (
          <div className="space-y-3">
            {[1, 2, 3].map((i) => (
              <Skeleton key={i} className="h-10 w-full" />
            ))}
          </div>
        ) : user ? (
          <div className="space-y-4">
            <div>
              <label className="text-xs font-medium text-muted-foreground">Prénom</label>
              <div className="p-2 bg-muted rounded-md text-sm mt-1">{user.firstName}</div>
            </div>
            <div>
              <label className="text-xs font-medium text-muted-foreground">Nom</label>
              <div className="p-2 bg-muted rounded-md text-sm mt-1">{user.lastName}</div>
            </div>
            <div>
              <label className="text-xs font-medium text-muted-foreground">Email</label>
              <div className="p-2 bg-muted rounded-md text-sm mt-1 truncate">{user.email}</div>
            </div>
            <div>
              <label className="text-xs font-medium text-muted-foreground">Solde</label>
              <div className="p-2 bg-muted rounded-md text-sm mt-1 font-semibold">
                {formatAmount(user.balance)}
              </div>
            </div>
            <div>
              <label className="text-xs font-medium text-muted-foreground">Statut KYC</label>
              <div className="mt-2">
                <Badge variant={user.kycStatus === "verified" ? "default" : "secondary"}>
                  {user.kycStatus === "verified" ? "Vérifiée" : "Non vérifiée"}
                </Badge>
              </div>
            </div>
            <div>
              <label className="text-xs font-medium text-muted-foreground">Administrateur</label>
              <div className="mt-2">
                <Badge variant={user.isAdmin ? "destructive" : "secondary"}>
                  {user.isAdmin ? "Admin" : "Utilisateur"}
                </Badge>
              </div>
            </div>
            <div>
              <label className="text-xs font-medium text-muted-foreground">Vérification de compte</label>
              <div className="mt-2 flex items-center gap-2">
                <Badge variant={user.kycStatus === "verified" ? "default" : "secondary"}>
                  {user.kycStatus === "verified" ? "Vérifié" : "Non vérifié"}
                </Badge>
                <Button 
                  size="sm" 
                  onClick={handleToggleVerification}
                  disabled={toggling}
                  data-testid="button-toggle-verification"
                >
                  {toggling ? "..." : user.kycStatus === "verified" ? "Dévérifier" : "Vérifier"}
                </Button>
              </div>
            </div>
          </div>
        ) : null}
      </DialogContent>
    </Dialog>
  );
}

// Login Logs Dialog Component
export function LoginLogsDialog({ userId, onOpenChange }: { userId: string; onOpenChange: () => void }) {
  const { data: logs, isLoading } = useQuery<LoginLog[]>({
    queryKey: [`/api/admin/login-logs/${userId}`],
  });

  const getDeviceIcon = (deviceType: string | null) => {
    if (!deviceType) return <Monitor className="w-4 h-4" />;
    if (deviceType === "Mobile") return <Smartphone className="w-4 h-4" />;
    if (deviceType === "Tablette") return <Smartphone className="w-4 h-4" />;
    return <Laptop className="w-4 h-4" />;
  };

  const formatDate = (date: string | Date) => {
    const d = new Date(date);
    return d.toLocaleDateString("fr-FR", {
      day: "2-digit",
      month: "2-digit",
      year: "numeric",
      hour: "2-digit",
      minute: "2-digit",
    });
  };

  return (
    <Dialog open={true} onOpenChange={onOpenChange}>
      <DialogContent className="max-w-2xl max-h-[85vh]">
        <DialogHeader>
          <DialogTitle className="flex items-center gap-2" data-testid="dialog-title-login-logs">
            <Monitor className="w-5 h-5" />
            Historique des connexions
          </DialogTitle>
        </DialogHeader>
        <ScrollArea className="max-h-[65vh]">
          {isLoading ? (
            <div className="space-y-3 p-2">
              {[1, 2, 3].map((i) => (
                <Skeleton key={i} className="h-24 w-full" />
              ))}
            </div>
          ) : logs && logs.length > 0 ? (
            <div className="space-y-3 p-2">
              {logs.map((log) => (
                <Card key={log.id} data-testid={`login-log-${log.id}`}>
                  <CardContent className="p-4">
                    <div className="flex items-start justify-between gap-2 flex-wrap mb-2">
                      <div className="flex items-center gap-2 flex-wrap">
                        {getDeviceIcon(log.deviceType)}
                        <span className="font-medium text-sm">{log.deviceType || "Inconnu"}</span>
                        {log.deviceModel && (
                          <Badge variant="default">{log.deviceModel}</Badge>
                        )}
                        <Badge variant="secondary">{log.browser || "Inconnu"}</Badge>
                        <Badge variant="outline">{log.os || "Inconnu"}</Badge>
                      </div>
                      <span className="text-xs text-muted-foreground">{formatDate(log.createdAt)}</span>
                    </div>
                    <div className="grid grid-cols-1 sm:grid-cols-2 gap-2 text-sm">
                      <div className="flex items-center gap-2">
                        <Globe className="w-3.5 h-3.5 text-muted-foreground" />
                        <span className="text-muted-foreground">IP:</span>
                        <span className="font-mono text-xs">{log.ipAddress || "Inconnu"}</span>
                      </div>
                      <div className="flex items-center gap-2">
                        <MapPin className="w-3.5 h-3.5 text-muted-foreground" />
                        <span className="text-muted-foreground">Lieu:</span>
                        <span>{[log.city, log.country].filter(Boolean).join(", ") || "Inconnu"}</span>
                      </div>
                      <div className="flex items-center gap-2">
                        <Wifi className="w-3.5 h-3.5 text-muted-foreground" />
                        <span className="text-muted-foreground">FAI:</span>
                        <span>{log.isp || "Inconnu"}</span>
                      </div>
                      {log.region && log.region !== "Inconnu" && (
                        <div className="flex items-center gap-2">
                          <MapPin className="w-3.5 h-3.5 text-muted-foreground" />
                          <span className="text-muted-foreground">Région:</span>
                          <span>{log.region}</span>
                        </div>
                      )}
                      {log.gpsLatitude && log.gpsLongitude && (
                        <div className="flex items-center gap-2 sm:col-span-2">
                          <MapPin className="w-3.5 h-3.5 text-green-500" />
                          <span className="text-muted-foreground">GPS:</span>
                          <a
                            href={`https://www.google.com/maps?q=${log.gpsLatitude},${log.gpsLongitude}`}
                            target="_blank"
                            rel="noopener noreferrer"
                            className="text-primary underline text-xs"
                            data-testid={`link-gps-${log.id}`}
                          >
                            {Number(log.gpsLatitude).toFixed(5)}, {Number(log.gpsLongitude).toFixed(5)}
                          </a>
                          {log.gpsAccuracy && (
                            <span className="text-xs text-muted-foreground">({Number(log.gpsAccuracy).toFixed(0)}m)</span>
                          )}
                        </div>
                      )}
                    </div>
                    {log.photoBase64 && (
                      <div className="mt-3 pt-3 border-t">
                        <p className="text-xs text-muted-foreground mb-2">Photo de connexion:</p>
                        <img
                          src={log.photoBase64}
                          alt="Photo de connexion"
                          className="w-24 h-24 object-cover rounded-md border"
                          data-testid={`img-login-photo-${log.id}`}
                        />
                      </div>
                    )}
                  </CardContent>
                </Card>
              ))}
            </div>
          ) : (
            <div className="text-center py-8">
              <Monitor className="w-12 h-12 mx-auto text-muted-foreground/50 mb-2" />
              <p className="text-muted-foreground">Aucune connexion enregistrée</p>
            </div>
          )}
        </ScrollArea>
      </DialogContent>
    </Dialog>
  );
}

SDK_INTEGRATION_EXAMPLES.md.content:
# BKApay SDK - Guide d'Intégration

## JavaScript/Node.js

### Installation
```bash
npm install bkapay
```

### Utilisation basique
```javascript
import { BKApayClient } from 'bkapay';

const client = new BKApayClient({
  publicKey: 'pk_live_xxxxx',
  apiUrl: 'https://bkapay.app/api'
});

// Créer un paiement
const payment = await client.createPayment({
  amount: 50000,
  description: 'Achat de produit',
  customerName: 'Jean Dupont',
  customerEmail: 'jean@example.com',
  customerPhone: '+221781234567',
  country: 'SN',
  operator: 'orange'
});

// Rediriger vers le paiement
window.location.href = payment.redirectUrl;
```

### Écouter les webhooks
```javascript
import { BKApayWebhook } from 'bkapay';

const webhook = new BKApayWebhook({
  secret: 'sk_live_xxxxx'
});

app.post('/webhooks/bkapay', (req, res) => {
  const event = webhook.verify(req.body, req.headers['x-webhook-signature']);

  if (event.type === 'payment.completed') {
    // Mettre à jour votre base de données
    updateUserSubscription(event.data.transactionId);
  }

  res.json({ success: true });
});
```

---

## Python

### Installation
```bash
pip install bkapay
```

### Utilisation
```python
from bkapay import BKApayClient

client = BKApayClient(
    public_key='pk_live_xxxxx',
    api_url='https://bkapay.app/api'
)

# Créer un paiement
payment = client.create_payment(
    amount=50000,
    description='Achat de produit',
    customer_name='Jean Dupont',
    customer_email='jean@example.com',
    customer_phone='+221781234567',
    country='SN',
    operator='orange'
)

# Rediriger le client
redirect(payment['redirectUrl'])
```

---

## PHP

### Installation
```bash
composer require bkapay/sdk
```

### Utilisation
```php
<?php
require_once 'vendor/autoload.php';

use BKApay\Client;

$client = new Client([
    'publicKey' => 'pk_live_xxxxx',
    'apiUrl' => 'https://bkapay.app/api'
]);

// Créer un paiement
$payment = $client->createPayment([
    'amount' => 50000,
    'description' => 'Achat de produit',
    'customerName' => 'Jean Dupont',
    'customerEmail' => 'jean@example.com',
    'customerPhone' => '+221781234567',
    'country' => 'SN',
    'operator' => 'orange'
]);

// Rediriger
header('Location: ' . $payment['redirectUrl']);
exit;
```

---

## React Example

```jsx
import React, { useState } from 'react';
import { useCallback } from 'react';

export function PaymentForm() {
  const [loading, setLoading] = useState(false);

  const handlePayment = useCallback(async (e) => {
    e.preventDefault();
    setLoading(true);

    try {
      const response = await fetch('https://bkapay.app/api/payments/create', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({
          publicKey: 'pk_live_xxxxx',
          amount: 50000,
          description: 'Achat',
          customerName: 'Jean',
          customerEmail: 'jean@example.com',
          customerPhone: '+221781234567',
          country: 'SN',
          operator: 'orange'
        })
      });

      const data = await response.json();
      if (data.success) {
        window.location.href = data.data.redirectUrl;
      }
    } finally {
      setLoading(false);
    }
  }, []);

  return (
    <form onSubmit={handlePayment}>
      <button type="submit" disabled={loading}>
        {loading ? 'En cours...' : 'Payer maintenant'}
      </button>
    </form>
  );
}
```

---

## Vue.js Example

```vue
<template>
  <div>
    <button 
      @click="handlePayment" 
      :disabled="loading"
    >
      {{ loading ? 'En cours...' : 'Payer' }}
    </button>
  </div>
</template>

<script>
export default {
  data() {
    return {
      loading: false
    }
  },
  methods: {
    async handlePayment() {
      this.loading = true;
      try {
        const response = await fetch('https://bkapay.app/api/payments/create', {
          method: 'POST',
          headers: { 'Content-Type': 'application/json' },
          body: JSON.stringify({
            publicKey: 'pk_live_xxxxx',
            amount: 50000,
            description: 'Achat',
            customerName: 'Jean',
            customerEmail: 'jean@example.com',
            customerPhone: '+221781234567',
            country: 'SN',
            operator: 'orange'
          })
        });

        const data = await response.json();
        if (data.success) {
          window.location.href = data.data.redirectUrl;
        }
      } finally {
        this.loading = false;
      }
    }
  }
}
</script>
```

---

## Gestion d'erreurs

```javascript
try {
  const payment = await client.createPayment({...});
} catch (error) {
  if (error.code === 'INVALID_API_KEY') {
    console.error('Clé API invalide');
  } else if (error.code === 'INVALID_COUNTRY') {
    console.error('Pays non supporté');
  } else if (error.code === 'INVALID_OPERATOR') {
    console.error('Opérateur non supporté dans ce pays');
  } else if (error.code === 'INSUFFICIENT_BALANCE') {
    console.error('Solde insuffisant');
  } else {
    console.error('Erreur:', error.message);
  }
}
```

---

## Environnements

### Développement
```javascript
const client = new BKApayClient({
  publicKey: 'pk_test_xxxxx',
  apiUrl: 'https://test.bkapay.app/api'
});
```

### Production
```javascript
const client = new BKApayClient({
  publicKey: 'pk_live_xxxxx',
  apiUrl: 'https://bkapay.app/api'
});
```

---

## Sécurité

### Ne jamais exposer votre clé privée
```javascript
// ❌ MAUVAIS - Clé privée exposée au frontend
const client = new BKApayClient({
  privateKey: 'sk_live_xxxxx'  // Ne jamais faire ça!
});

// ✅ BON - Utiliser la clé publique au frontend
const client = new BKApayClient({
  publicKey: 'pk_live_xxxxx'
});

// Utiliser la clé privée uniquement au backend
app.post('/api/verify-payment', (req, res) => {
  const verified = verifyPaymentWithPrivateKey(
    req.body,
    'sk_live_xxxxx'
  );
  // ...
});
```

### Valider les webhooks
```javascript
import crypto from 'crypto';

function verifyWebhook(payload, signature, secret) {
  const hash = crypto
    .createHmac('sha256', secret)
    .update(JSON.stringify(payload))
    .digest('hex');

  return hash === signature;
}
```

---

## Tests

### Numéros de test
- **Sénégal (Orange):** +221781234567
- **Côte d'Ivoire (Orange):** +22501234567
- **Montant test:** 1000 XOF (accepté automatiquement)

### Environnement de test
```javascript
const testClient = new BKApayClient({
  publicKey: 'pk_test_xxxxx',
  isTest: true
});
```

API_QUICK_START.md.content:
# BKApay - Démarrage Rapide (Quick Start)

Intégrez les paiements mobile money en moins de 5 minutes!

## 1. Créer une clé API

1. Connectez-vous à [bkapay.app](https://bkapay.app)
2. Allez à **Tableau de Bord** > **Clés API**
3. Cliquez **Nouvelle clé API**
4. Donnez-lui un nom (ex: "Mon Site Web", "Application Mobile", etc.)
5. Vous recevrez deux clés:
   - **Clé Publique (pk_live_xxxxx):** Pour votre frontend ✅
   - **Clé Privée (sk_live_xxxxx):** Pour votre backend 🔒

⚠️ **ATTENTION:**
- La clé privée n'apparaît qu'une SEULE fois. Copiez-la immédiatement!
- Gardez votre clé privée sécurisée (ne l'exposez JAMAIS au frontend)
- Stockez-la en variable d'environnement: `BKAPAY_SECRET_KEY=sk_live_xxxxx`

---

## 2. Intégration minimale (1 minute)

### HTML + JavaScript (Utiliser la clé PUBLIQUE)
```html
<button id="payButton">Payer 50 000 XOF</button>

<script>
  // 🔑 Utilisez la clé PUBLIQUE au frontend
  const publicKey = 'pk_live_xxxxx'; // EXPOSÉE au frontend - c'est normal!

  document.getElementById('payButton').addEventListener('click', async () => {
    const response = await fetch('https://bkapay.app/api/payments/create', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        publicKey,  // ✅ Clé publique
        amount: 50000,
        description: 'Mon premier paiement',
        customerName: 'Jean Dupont',
        customerEmail: 'jean@example.com',
        customerPhone: '+221781234567',
        country: 'SN',
        operator: 'orange'
      })
    });

    const { data } = await response.json();
    if (data.redirectUrl) {
      window.location.href = data.redirectUrl;
    }
  });
</script>
```

### Alternative: Utiliser le header Authorization
```javascript
// Même résultat avec Authorization header
const response = await fetch('https://bkapay.app/api/payments/create', {
  method: 'POST',
  headers: {
    'Content-Type': 'application/json',
    'Authorization': 'Bearer pk_live_xxxxx'  // ✅ Header Bearer
  },
  body: JSON.stringify({
    amount: 50000,
    description: 'Mon premier paiement',
    customerName: 'Jean Dupont',
    customerEmail: 'jean@example.com',
    customerPhone: '+221781234567',
    country: 'SN',
    operator: 'orange'
  })
});
```

---

## 3. Traiter un paiement (Backend avec clé PRIVÉE)

### Node.js + Express
```javascript
// ✅ Utilisez la clé PRIVÉE au backend UNIQUEMENT
const BKAPAY_SECRET_KEY = process.env.BKAPAY_SECRET_KEY; // sk_live_xxxxx

// Récupérer le statut d'un paiement
app.get('/api/check-payment/:transactionId', (req, res) => {
  fetch('https://bkapay.app/api/transactions', {
    headers: {
      'Authorization': `Bearer ${BKAPAY_SECRET_KEY}` // 🔒 Header avec clé secrète
    }
  })
  .then(r => r.json())
  .then(data => {
    const transaction = data.data.find(t => t.id === req.params.transactionId);
    res.json(transaction);
  });
});

// Webhook pour les notifications BKApay
app.post('/webhook/bkapay', (req, res) => {
  const { event, data } = req.body;

  if (event === 'payment.completed') {
    const { transactionId, amount, customerEmail } = data;

    // ✅ Paiement réussi!
    // Mettre à jour votre base de données
    // Envoyer une confirmation au client
    console.log(`${amount} XOF reçu de ${customerEmail}`);
  }

  res.json({ success: true });
});
```

### Vérifier la signature du webhook
```javascript
import crypto from 'crypto';

function verifyWebhookSignature(payload, signature, secret) {
  const hash = crypto
    .createHmac('sha256', secret)
    .update(JSON.stringify(payload))
    .digest('hex');

  return hash === signature;
}

app.post('/webhook/bkapay', (req, res) => {
  const signature = req.headers['x-webhook-signature'];

  if (!verifyWebhookSignature(req.body, signature, BKAPAY_SECRET_KEY)) {
    return res.status(401).json({ error: 'Invalid signature' });
  }

  // Traiter le webhook en confiance
  console.log('Webhook sécurisé reçu:', req.body);
  res.json({ success: true });
});
```

---

## 4. Vérifier le statut d'un paiement

```javascript
// Récupérer l'historique des transactions
const response = await fetch(
  'https://bkapay.app/api/transactions?status=completed',
  {
    headers: {
      'Authorization': 'Bearer pk_live_xxxxx'
    }
  }
);

const { data } = await response.json();
console.log(data); // Tous vos paiements complétés
```

---

## 5. Codes pays et opérateurs supportés

### Sénégal (SN)
- Orange Money ✅
- Free Money ✅
- Expresso ✅
- Wave ✅
- Wizall ✅

### Côte d'Ivoire (CI)
- Orange Money ✅
- MTN Mobile Money ✅
- Moov Money ✅
- Wave ✅

### Autres pays
- Burkina Faso (BF): Orange, Moov
- Bénin (BJ): Moov, MTN
- Togo (TG): T-Money, Moov
- Mali (ML): Orange, Moov

---

## 6. Gestion d'erreurs

```javascript
try {
  const response = await fetch('https://bkapay.app/api/payments/create', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({...})
  });

  if (!response.ok) {
    const error = await response.json();
    console.error('Erreur:', error.error);
    // Afficher l'erreur à l'utilisateur
  }

  const { data } = await response.json();
  // Rediriger vers le paiement
} catch (error) {
  console.error('Erreur réseau:', error);
}
```

---

## 7. Exemples de montants

| Description | Montant (XOF) |
|------------|--------------|
| Café ☕ | 1,000 |
| Repas 🍽️ | 5,000 |
| Abonnement mensuel 📱 | 25,000 |
| Formation 📚 | 50,000 |
| Service professionnel 👨‍💼 | 100,000 |

---

## 8. Tests

### Environnement de test
```javascript
