              </p>
            </div>
            {demoTransaction.description && (
              <div>
                <p className="text-sm text-muted-foreground">Description</p>
                <p className="text-sm text-foreground font-medium">{demoTransaction.description}</p>
              </div>
            )}
            {demoTransaction.customerName && (
