import { useParams, useLocation } from "wouter";
import { useQuery } from "@tanstack/react-query";
import { useEffect, useState, useRef } from "react";
import { Card, CardContent } from "@/components/ui/card";
import { CheckCircle2, XCircle, Loader2 } from "lucide-react";
import type { Transaction } from "@shared/schema";
import logoImage from "@assets/bkapay-logo.png";

const COUNTDOWN_DURATION = 5 * 60; // 5 minutes in seconds

function getStorageKey(transactionId: string): string {
  return `payment_countdown_tx_${transactionId}`;
}

function getStartTime(key: string): number | null {
  const stored = localStorage.getItem(key);
  if (stored) {
    return parseInt(stored, 10);
  }
  return null;
}

function setStartTime(key: string, time: number): void {
  localStorage.setItem(key, time.toString());
}

function clearStartTime(key: string): void {
  localStorage.removeItem(key);
}

function calculateRemainingTime(startTime: number): number {
  const elapsed = Math.floor((Date.now() - startTime) / 1000);
  return Math.max(0, COUNTDOWN_DURATION - elapsed);
}

function formatTime(seconds: number): string {
  const mins = Math.floor(seconds / 60);
  const secs = seconds % 60;
  return `${mins}:${secs.toString().padStart(2, "0")}`;
}

export default function PaymentStatus() {
  const { transactionId } = useParams<{ transactionId: string }>();
  const [, setLocation] = useLocation();
  const [remainingTime, setRemainingTime] = useState(COUNTDOWN_DURATION);
  const [isExpired, setIsExpired] = useState(false);
  const timerRef = useRef<NodeJS.Timeout | null>(null);

  const storageKey = transactionId ? getStorageKey(transactionId) : "";

  // Initialize countdown from localStorage or start new
  useEffect(() => {
    if (!transactionId) return;

    let startTime = getStartTime(storageKey);
    if (!startTime) {
      startTime = Date.now();
      setStartTime(storageKey, startTime);
    }

    const remaining = calculateRemainingTime(startTime);
    setRemainingTime(remaining);
    setIsExpired(remaining <= 0);
  }, [transactionId, storageKey]);

  // Query with polling every second
  const { data: transaction, isLoading } = useQuery<Transaction>({
    queryKey: [`/api/transactions/${transactionId}`],
    enabled: !!transactionId && !isExpired,
    refetchInterval: (query) => {
      if (query.state.data?.status === "completed" || query.state.data?.status === "failed") {
        return false;
      }
      return 1000; // Poll every 1 second
    },
  });

  // Countdown timer effect
  useEffect(() => {
    if (!transactionId || transaction?.status === "completed" || transaction?.status === "failed") {
      return;
    }

    timerRef.current = setInterval(() => {
      const storedStartTime = getStartTime(storageKey);
      if (!storedStartTime) return;

      const remaining = calculateRemainingTime(storedStartTime);
      setRemainingTime(remaining);

      if (remaining <= 0) {
        setIsExpired(true);
        if (timerRef.current) {
          clearInterval(timerRef.current);
        }
      }
    }, 1000);

    return () => {
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    };
  }, [transactionId, storageKey, transaction?.status]);

  // Clear countdown when payment completed or failed
  useEffect(() => {
    if (transaction?.status === "completed" || transaction?.status === "failed") {
      clearStartTime(storageKey);
      if (timerRef.current) {
        clearInterval(timerRef.current);
      }
    }
  }, [transaction?.status, storageKey]);

  // Redirect to callback URL when payment is completed or failed
  useEffect(() => {
    if (!transaction) return;

    const metadata = transaction.metadata ? JSON.parse(transaction.metadata) : {};
    const callbackUrl = metadata?.callbackUrl;

    if (transaction.status === "completed" && callbackUrl) {
      const url = new URL(callbackUrl);
      url.searchParams.append("status", "success");
      url.searchParams.append("transactionId", transaction.id);
      url.searchParams.append("amount", String(transaction.amount));
      window.location.href = url.toString();
    } else if (transaction.status === "failed" && callbackUrl) {
      const url = new URL(callbackUrl);
      url.searchParams.append("status", "failed");
      url.searchParams.append("transactionId", transaction.id);
      url.searchParams.append("amount", String(transaction.amount));
      window.location.href = url.toString();
    }
  }, [transaction]);

  const formatAmount = (amount: number) => {
    return new Intl.NumberFormat("fr-FR", {
      style: "currency",
      currency: "XOF",
      minimumFractionDigits: 0,
      maximumFractionDigits: 0,
    }).format(amount);
  };

  // Loading state
  if (isLoading && !transaction) {
    return (
      <div className="w-full min-h-screen bg-gradient-to-br from-primary/5 via-background to-accent/5 flex items-center justify-center p-4 overflow-hidden">
        <Card className="w-full max-w-sm">
          <CardContent className="pt-8 pb-8 flex flex-col items-center text-center space-y-6">
            <img src={logoImage} alt="BKApay" className="h-10 w-auto" />

            <Loader2 className="w-12 h-12 text-primary animate-spin" />

            <div className="space-y-2">
              <h2 className="text-xl font-bold text-foreground">Chargement...</h2>
            </div>
          </CardContent>
        </Card>
      </div>
    );
  }

  // Transaction not found
  if (!transaction) {
    return (
      <div className="w-full min-h-screen bg-gradient-to-br from-primary/5 via-background to-accent/5 flex items-center justify-center p-4 overflow-hidden">
        <Card className="w-full max-w-sm">
          <CardContent className="pt-8 pb-8 flex flex-col items-center text-center space-y-4">
            <img src={logoImage} alt="BKApay" className="h-10 w-auto" />
            <p className="text-muted-foreground">Transaction non trouvée</p>
          </CardContent>
        </Card>
      </div>
    );
  }

  // Payment completed - Show success logo only (no buttons)
  if (transaction.status === "completed") {
    return (
      <div className="w-full min-h-screen bg-gradient-to-br from-primary/5 via-background to-accent/5 flex items-center justify-center p-4 overflow-hidden">
        <Card className="w-full max-w-sm">
          <CardContent className="pt-8 pb-8 flex flex-col items-center text-center space-y-6">
            <img src={logoImage} alt="BKApay" className="h-10 w-auto" />

            <div className="w-24 h-24 rounded-full bg-green-100 dark:bg-green-950 flex items-center justify-center">
              <CheckCircle2 className="w-16 h-16 text-green-600 dark:text-green-400" data-testid="icon-success" />
            </div>

            <div className="space-y-2">
              <h2 className="text-2xl font-bold text-green-600 dark:text-green-400">Paiement Réussi</h2>
              <p className="text-sm text-muted-foreground">Votre transaction a été confirmée avec succès</p>
            </div>

            <div className="w-full bg-muted rounded-lg p-4 space-y-3">
              <div className="flex justify-between items-center">
                <span className="text-sm text-muted-foreground">Montant</span>
                <span className="font-semibold text-foreground">{formatAmount(transaction.amount)}</span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-sm text-muted-foreground">Référence</span>
                <span className="font-mono text-sm text-foreground">{transaction.id.substring(0, 8)}</span>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    );
  }

  // Payment failed or expired - Show error logo only (no buttons)
  if (transaction.status === "failed" || isExpired) {
    return (
      <div className="w-full min-h-screen bg-gradient-to-br from-primary/5 via-background to-accent/5 flex items-center justify-center p-4 overflow-hidden">
        <Card className="w-full max-w-sm">
          <CardContent className="pt-8 pb-8 flex flex-col items-center text-center space-y-6">
            <img src={logoImage} alt="BKApay" className="h-10 w-auto" />

            <div className="w-24 h-24 rounded-full bg-red-100 dark:bg-red-950 flex items-center justify-center">
              <XCircle className="w-16 h-16 text-red-600 dark:text-red-400" data-testid="icon-failed" />
            </div>

            <div className="space-y-2">
              <h2 className="text-2xl font-bold text-red-600 dark:text-red-400">Paiement Échoué</h2>
              <p className="text-sm text-muted-foreground">
                {isExpired ? "Le délai de validation a expiré" : "La transaction n'a pas pu être complétée"}
              </p>
            </div>

            <div className="w-full bg-muted rounded-lg p-4 space-y-3">
              <div className="flex justify-between items-center">
                <span className="text-sm text-muted-foreground">Montant</span>
                <span className="font-semibold text-foreground">{formatAmount(transaction.amount)}</span>
              </div>
              <div className="flex justify-between items-center">
                <span className="text-sm text-muted-foreground">Référence</span>
                <span className="font-mono text-sm text-foreground">{transaction.id.substring(0, 8)}</span>
              </div>
            </div>
          </CardContent>
        </Card>
      </div>
    );
  }

  // Payment pending - Show countdown timer
  return (
    <div className="w-full min-h-screen bg-gradient-to-br from-primary/5 via-background to-accent/5 flex items-center justify-center p-4 overflow-hidden">
      <Card className="w-full max-w-sm">
        <CardContent className="pt-8 pb-8 flex flex-col items-center text-center space-y-6">
          <img src={logoImage} alt="BKApay" className="h-10 w-auto" />

          <div className="space-y-4">
            <Loader2 className="w-16 h-16 text-primary animate-spin mx-auto" data-testid="icon-polling" />

            <div className="space-y-2">
              <h2 className="text-xl font-bold text-foreground">Paiement en cours</h2>
              <p className="text-sm text-muted-foreground">
                Veuillez confirmer la transaction sur votre téléphone
              </p>
            </div>

            {/* Countdown Timer */}
            <div className="bg-primary/10 rounded-lg p-4">
              <p className="text-sm text-muted-foreground mb-1">Temps restant</p>
              <p className="text-3xl font-mono font-bold text-primary" data-testid="text-countdown">
                {formatTime(remainingTime)}
              </p>
            </div>

            <div className="w-full bg-muted rounded-lg p-4 space-y-3">
              <div className="flex justify-between items-center">
                <span className="text-sm text-muted-foreground">Montant</span>
                <span className="font-semibold text-foreground">{formatAmount(transaction.amount)}</span>
              </div>
              {transaction.description && (
                <div className="flex justify-between items-center">
                  <span className="text-sm text-muted-foreground">Détail</span>
                  <span className="text-sm text-foreground truncate max-w-[150px]">{transaction.description}</span>
                </div>
              )}
            </div>

            <p className="text-xs text-muted-foreground">
              Ne fermez pas cette page
            </p>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

client/src/pages/dashboard/kyc-history.t.content:
import { useQuery } from "@tanstack/react-query";
import { Button } from "@/components/ui/button";
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { Tabs, TabsContent, TabsList, TabsTrigger } from "@/components/ui/tabs";
import { Input } from "@/components/ui/input";
import { CheckCircle2, X, ArrowLeft, Search, Download, Clock, BadgeCheck } from "lucide-react";
import { Badge } from "@/components/ui/badge";
import type { User } from "@shared/schema";
import { useLocation } from "wouter";
import { useState } from "react";

export default function KycHistoryPage() {
  const [, navigate] = useLocation();
  const [searchQuery, setSearchQuery] = useState("");

  const { data: submissions } = useQuery({
    queryKey: ["/api/admin/kyc-submissions"],
  });

  const approvedSubmissions = (submissions as User[] || []).filter(
    (u: User) => u.kycStatus === "verified"
  );

  const rejectedSubmissions = (submissions as User[] || []).filter(
    (u: User) => u.kycStatus === "rejected"
  );

  const pendingSubmissions = (submissions as User[] || []).filter(
    (u: User) => u.kycStatus === "submitted"
  );

  const filterBySearch = (users: User[]): User[] => {
    if (!searchQuery.trim()) return users;
    const query = searchQuery.toLowerCase();
    return users.filter((u: User) => {
      const fullName = `${u.firstName} ${u.lastName}`.toLowerCase();
      const email = u.email.toLowerCase();
      return fullName.includes(query) || email.includes(query);
    });
  };

  const filteredApproved = filterBySearch(approvedSubmissions);
  const filteredRejected = filterBySearch(rejectedSubmissions);
  const filteredPending = filterBySearch(pendingSubmissions);

  const downloadKycPDF = (user: User) => {
    // Generate a simple text-based KYC record and download as text file
    const content = `FORMULAIRE DE VÉRIFICATION D'IDENTITÉ (KYC)
=====================================

Date de traitement: ${new Date().toLocaleDateString("fr-FR", { year: "numeric", month: "long", day: "numeric" })}

INFORMATIONS PERSONNELLES
----------------------------
Nom: ${user.lastName}
Prénom: ${user.firstName}
Email: ${user.email}

STATUT DE VÉRIFICATION
------------------------
Statut: ${user.kycStatus === "verified" ? "APPROUVÉE" : user.kycStatus === "rejected" ? "REJETÉE" : "EN ATTENTE"}
Date de soumission: ${new Date(user.createdAt).toLocaleDateString("fr-FR", { year: "numeric", month: "long", day: "numeric", hour: "2-digit", minute: "2-digit" })}

${user.kycRejectionReason ? `\nRAISON DU REJET\n------------------\n${user.kycRejectionReason}\n` : ""}

DOCUMENTS FOURNIS
------------------
- Photo d'identité recto: ${user.kycIdFront ? "✓ Fourni" : "✗ Non fourni"}
- Photo d'identité verso: ${user.kycIdBack ? "✓ Fourni" : "✗ Non fourni"}
- Selfie: ${user.kycSelfie ? "✓ Fourni" : "✗ Non fourni"}

Note: Ce document certifie que les documents d'identité ont été soumis et traités conformément aux processus de BKApay.`;

    const element = document.createElement("a");
    const file = new Blob([content], { type: "text/plain" });
    element.href = URL.createObjectURL(file);
    element.download = `KYC_${user.firstName}_${user.lastName}_${new Date().getTime()}.txt`;
    document.body.appendChild(element);
    element.click();
    document.body.removeChild(element);
  };

  const renderSubmissionCard = (user: User) => (
    <Card key={user.id} className="overflow-hidden" data-testid={`kyc-history-card-${user.id}`}>
      <CardHeader className="pb-3">
        <div className="flex items-start justify-between gap-4">
          <div className="flex-1">
            <div className="flex items-center gap-2 flex-wrap">
              <CardTitle className="text-lg">
                {user.firstName} {user.lastName}
              </CardTitle>
              {user.kycStatus === "verified" && (
                <Badge variant="default" className="bg-green-600 hover:bg-green-600 gap-1">
                  <BadgeCheck className="w-3 h-3" />
                  Vérifié
                </Badge>
              )}
            </div>
            <p className="text-sm text-muted-foreground mt-1">{user.email}</p>
            <p className="text-xs text-muted-foreground mt-1">
              {new Date(user.createdAt).toLocaleDateString("fr-FR", { year: "numeric", month: "long", day: "numeric", hour: "2-digit", minute: "2-digit" })}
            </p>
          </div>
          <div className="flex flex-col gap-2 items-end">
            {user.kycStatus === "verified" && (
              <div className="flex items-center gap-1 px-2 py-1 rounded-full bg-green-100 dark:bg-green-950">
                <CheckCircle2 className="w-4 h-4 text-green-600 dark:text-green-400" />
                <span className="text-xs font-medium text-green-700 dark:text-green-300">Approuvée</span>
              </div>
            )}
            {user.kycStatus === "rejected" && (
              <div className="flex items-center gap-1 px-2 py-1 rounded-full bg-red-100 dark:bg-red-950">
                <X className="w-4 h-4 text-red-600 dark:text-red-400" />
                <span className="text-xs font-medium text-red-700 dark:text-red-300">Rejetée</span>
              </div>
            )}
            {user.kycStatus === "submitted" && (
              <div className="flex items-center gap-1 px-2 py-1 rounded-full bg-yellow-100 dark:bg-yellow-950">
                <Clock className="w-4 h-4 text-yellow-600 dark:text-yellow-400" />
                <span className="text-xs font-medium text-yellow-700 dark:text-yellow-300">En attente</span>
              </div>
            )}
            <Button
              size="sm"
              variant="outline"
              onClick={() => downloadKycPDF(user)}
              className="gap-2"
              data-testid={`button-download-kyc-${user.id}`}
            >
              <Download className="w-3 h-3" />
              Télécharger
            </Button>
          </div>
        </div>
      </CardHeader>
      <CardContent className="space-y-6">
        {user.kycRejectionReason && (
          <div className="bg-red-50 dark:bg-red-950/30 border border-red-200 dark:border-red-900 rounded-lg p-3">
            <p className="text-sm text-red-700 dark:text-red-300">
              <strong>Raison du rejet:</strong> {user.kycRejectionReason}
            </p>
          </div>
        )}

        <div>
          <h4 className="font-semibold text-sm mb-3">Documents fournis</h4>
          <div className="grid grid-cols-1 sm:grid-cols-3 gap-3">
            {user.kycIdFront && (
              <div className="border rounded-lg p-2 overflow-hidden">
                <p className="text-xs font-medium text-muted-foreground mb-2">ID Recto</p>
                <img
                  src={user.kycIdFront}
                  alt="ID Front"
                  className="w-full h-32 object-cover rounded"
                />
              </div>
            )}
            {user.kycIdBack && (
              <div className="border rounded-lg p-2 overflow-hidden">
                <p className="text-xs font-medium text-muted-foreground mb-2">ID Verso</p>
                <img
                  src={user.kycIdBack}
                  alt="ID Back"
                  className="w-full h-32 object-cover rounded"
                />
              </div>
            )}
            {user.kycSelfie && (
              <div className="border rounded-lg p-2 overflow-hidden">
                <p className="text-xs font-medium text-muted-foreground mb-2">Selfie</p>
                <img
                  src={user.kycSelfie}
                  alt="Selfie"
                  className="w-full h-32 object-cover rounded"
                />
              </div>
            )}
          </div>
        </div>
      </CardContent>
    </Card>
  );

  return (
    <div className="space-y-6">
      <div className="flex items-center gap-3">
        <Button
          variant="ghost"
          size="sm"
          onClick={() => navigate("/dashboard/management")}
          data-testid="button-back-to-management"
        >
          <ArrowLeft className="w-4 h-4 mr-2" />
          Retour
        </Button>
        <div>
          <h1 className="text-2xl font-bold text-foreground">Historique KYC</h1>
          <p className="text-sm text-muted-foreground">Vérifications approuvées et rejetées</p>
        </div>
      </div>

      <div className="relative">
        <Search className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-muted-foreground" />
        <Input
          placeholder="Rechercher par nom, prénom ou email..."
          value={searchQuery}
          onChange={(e) => setSearchQuery(e.target.value)}
          className="pl-10"
          data-testid="input-search-kyc"
        />
      </div>

      <Tabs defaultValue="approved" className="w-full">
        <TabsList className="grid w-full grid-cols-3">
          <TabsTrigger value="approved" data-testid="tab-kyc-approved">
            Approuvées ({filteredApproved.length})
          </TabsTrigger>
          <TabsTrigger value="rejected" data-testid="tab-kyc-rejected">
            Rejetées ({filteredRejected.length})
          </TabsTrigger>
          <TabsTrigger value="pending" data-testid="tab-kyc-pending">
            En attente ({filteredPending.length})
          </TabsTrigger>
        </TabsList>

        <TabsContent value="approved" className="space-y-4 mt-4">
          {filteredApproved.length === 0 ? (
            <Card>
              <CardContent className="pt-6 text-center py-12">
                <CheckCircle2 className="w-12 h-12 mx-auto mb-3 text-green-600 dark:text-green-400" />
                <p className="text-muted-foreground">
                  {searchQuery ? "Aucune vérification approuvée trouvée" : "Aucune vérification approuvée"}
                </p>
              </CardContent>
            </Card>
          ) : (
            <div className="grid gap-4">
              {filteredApproved.map((user: User) => renderSubmissionCard(user))}
            </div>
          )}
        </TabsContent>

        <TabsContent value="rejected" className="space-y-4 mt-4">
          {filteredRejected.length === 0 ? (
            <Card>
              <CardContent className="pt-6 text-center py-12">
                <X className="w-12 h-12 mx-auto mb-3 text-red-600 dark:text-red-400" />
                <p className="text-muted-foreground">
                  {searchQuery ? "Aucune vérification rejetée trouvée" : "Aucune vérification rejetée"}
                </p>
              </CardContent>
            </Card>
          ) : (
            <div className="grid gap-4">
              {filteredRejected.map((user: User) => renderSubmissionCard(user))}
            </div>
          )}
        </TabsContent>

        <TabsContent value="pending" className="space-y-4 mt-4">
          {filteredPending.length === 0 ? (
            <Card>
              <CardContent className="pt-6 text-center py-12">
                <Clock className="w-12 h-12 mx-auto mb-3 text-yellow-600 dark:text-yellow-400" />
                <p className="text-muted-foreground">
                  {searchQuery ? "Aucune vérification en attente trouvée" : "Aucune vérification en attente"}
                </p>
              </CardContent>
            </Card>
          ) : (
            <div className="grid gap-4">
              {filteredPending.map((user: User) => renderSubmissionCard(user))}
            </div>
          )}
        </TabsContent>
      </Tabs>
    </div>
  );
}

server/utils/fees.ts.content:
/**
 * BKApay Fee Calculation System
 * 
 * DYNAMIC FEES: Configurable per country and operator via admin dashboard
 * Default: 6% for ALL countries and operators if not configured
 * 
 * CRITICAL LOGIC:
 * 
 * INCOMING PAYMENTS (deposits, payment links, merchant links, API):
 * - Client pays GROSS amount (e.g., 2000 XOF) to provider
 * - Provider validates GROSS amount (SMS confirms 2000)
 * - Transaction records GROSS amount (2000)
 * - BKApay takes fee (e.g., 6% = 120 XOF)
 * - User receives NET amount (1880 XOF)
 * - History displays: "Dépôt de 2000 XOF"
 * - Balance credited: 1880 XOF
 * 
 * OUTGOING PAYMENTS (withdrawals, transfers):
 * - User requests GROSS amount (e.g., 10000 XOF)
 * - Fee is subtracted from amount (e.g., 6% = 600)
 * - User receives NET amount (9400)
 * - Balance debited: GROSS amount (10000)
 * - History displays: "Retrait de 10000 XOF"
 */

const DEFAULT_FEE_PERCENTAGE = 60; // 6% as default

/**
 * Get fee percentage - returns the value directly
 * Use getFeeFromDatabase for dynamic fees from database
 */
export function getFeePercentage(feeValue?: number): number {
  return feeValue ?? DEFAULT_FEE_PERCENTAGE;
}

/**
 * Get the active provider for INCOMING payments (deposits, payment links, etc.)
 * Uses BOTH operator-level (incomingEnabled) AND country-level (payinEnabled) checks
 * Returns the provider name (lowercase) or 'paydunya' as default
 */
export async function getActiveProviderForCountry(storage: any, country: string, operator?: string): Promise<string> {
  try {
    const [configs, countryStatuses, providerConfigs] = await Promise.all([
      storage.getCountryOperatorConfigs(),
      storage.getCountryStatuses(),
      storage.getProviderConfigs(),
    ]);

    // First check which providers are globally active
    const activeProviders = new Set(
      providerConfigs.filter((p: any) => p.isActive).map((p: any) => p.provider)
    );

    // If operator is provided, check operator-level config first
    if (operator) {
      const enabledConfigs = configs.filter((c: any) => 
        c.country.toUpperCase() === country.toUpperCase() &&
        c.operator.toLowerCase() === operator.toLowerCase() &&
        c.incomingEnabled &&
        activeProviders.has(c.provider)
      );

      const enabledCountries = countryStatuses.filter((cs: any) =>
        cs.country.toUpperCase() === country.toUpperCase() &&
        cs.payinEnabled &&
        activeProviders.has(cs.provider)
      );

      // Find provider that has both operator-level and country-level enabled
      for (const config of enabledConfigs) {
        const hasCountryLevel = enabledCountries.some((c: any) => c.provider === config.provider);
        if (hasCountryLevel) {
          return config.provider.toLowerCase();
        }
      }

      // If only operator-level is configured, use that
      if (enabledConfigs.length > 0) {
        return enabledConfigs[0].provider.toLowerCase();
      }
    }

    // Fallback to country-level only
    const activeStatus = countryStatuses.find((status: any) => 
      status.country === country.toUpperCase() && 
      status.payinEnabled === true &&
      activeProviders.has(status.provider)
    );

    if (activeStatus && activeStatus.provider) {
      return activeStatus.provider.toLowerCase();
    }
  } catch (error) {
    console.warn(`[FEES] Failed to get active payin provider for ${country}/${operator}:`, error);
  }
  return 'paydunya'; // Default fallback
}

/**
 * Get the active provider for OUTGOING payments (withdrawals, transfers)
 * Uses BOTH operator-level (outgoingEnabled) AND country-level (payoutEnabled) checks
 * Returns the provider name (lowercase) or 'paydunya' as default
 */
export async function getActivePayoutProviderForCountry(storage: any, country: string, operator?: string): Promise<string> {
  try {
    const [configs, countryStatuses, providerConfigs] = await Promise.all([
      storage.getCountryOperatorConfigs(),
      storage.getCountryStatuses(),
      storage.getProviderConfigs(),
    ]);

    const activeProviders = new Set(
      providerConfigs.filter((p: any) => p.isActive).map((p: any) => p.provider)
    );

    // If operator is provided, check operator-level config first
    if (operator) {
      const enabledConfigs = configs.filter((c: any) => 
        c.country.toUpperCase() === country.toUpperCase() &&
        c.operator.toLowerCase() === operator.toLowerCase() &&
        c.outgoingEnabled &&
        activeProviders.has(c.provider)
      );

      const enabledCountries = countryStatuses.filter((cs: any) =>
        cs.country.toUpperCase() === country.toUpperCase() &&
        cs.payoutEnabled &&
        activeProviders.has(cs.provider)
      );

      // Find provider that has both operator-level and country-level enabled
      for (const config of enabledConfigs) {
        const hasCountryLevel = enabledCountries.some((c: any) => c.provider === config.provider);
        if (hasCountryLevel) {
          return config.provider.toLowerCase();
        }
      }

      // If only operator-level is configured, use that
      if (enabledConfigs.length > 0) {
        return enabledConfigs[0].provider.toLowerCase();
      }
    }

    // Fallback to country-level only
    const activeStatus = countryStatuses.find((status: any) => 
      status.country === country.toUpperCase() && 
      status.payoutEnabled === true &&
      activeProviders.has(status.provider)
    );

    if (activeStatus && activeStatus.provider) {
      return activeStatus.provider.toLowerCase();
    }
  } catch (error) {
    console.warn(`[FEES] Failed to get active payout provider for ${country}/${operator}:`, error);
  }
  return 'paydunya'; // Default fallback
}

/**
 * Get fees for INCOMING payments (deposits, payment links, merchant links, API)
 * Automatically detects the active payin provider using operator-level config
 */
export async function getDynamicFees(
  storage: any,
  country: string,
  operator: string
): Promise<{ incoming: number; outgoing: number; provider: string }> {
  const provider = await getActiveProviderForCountry(storage, country, operator);
  const fees = await getFeeFromDatabase(storage, provider, country, operator);
  return {
    ...fees,
    provider,
  };
}

/**
 * Get fees for OUTGOING payments (withdrawals, transfers)
 * Automatically detects the active payout provider using operator-level config
 */
export async function getDynamicOutgoingFees(
  storage: any,
  country: string,
  operator: string
): Promise<{ incoming: number; outgoing: number; provider: string }> {
  const provider = await getActivePayoutProviderForCountry(storage, country, operator);
  const fees = await getFeeFromDatabase(storage, provider, country, operator);
  return {
    ...fees,
    provider,
  };
}

/**
 * Get fee percentages from database for a specific provider/country/operator
 * Returns incoming and outgoing fee percentages
 */
export async function getFeeFromDatabase(
  storage: any, 
  provider: string,
  country: string, 
  operator: string
): Promise<{ incoming: number; outgoing: number }> {
  try {
    const config = await storage.getFeeConfig(provider.toLowerCase(), country.toUpperCase(), operator.toLowerCase());
    if (config) {
      return {
        incoming: config.incomingFeePercentage ?? DEFAULT_FEE_PERCENTAGE,
        outgoing: config.outgoingFeePercentage ?? DEFAULT_FEE_PERCENTAGE,
      };
    }
  } catch (error) {
    console.warn(`[FEES] Failed to get fee config for ${provider}/${country}/${operator}:`, error);
  }
  return { incoming: DEFAULT_FEE_PERCENTAGE, outgoing: DEFAULT_FEE_PERCENTAGE };
}

/**
 * Calculate fees for INCOMING payments (deposits, payment links, etc.)
 * 
 * @param grossAmount - The GROSS amount the client pays (e.g., 2000)
 * @param feePercentageValue - Fee percentage from database (60 = 6%) or undefined for default
 * @returns {grossAmount: 2000, feeAmount: 120, netAmount: 1880}
 * 
 * Usage:
 * - Store grossAmount in transaction.amount
 * - Credit netAmount to user balance
 * - Display grossAmount in transaction history
 */
export function calculateIncomingFee(grossAmount: number, feePercentageValue?: number): {
  grossAmount: number;
  feeAmount: number;
  feePercentage: number;
  netAmount: number;
} {
  const feePercentage = getFeePercentage(feePercentageValue);
  const feeAmount = Math.floor((grossAmount * feePercentage) / 1000);
  const netAmount = grossAmount - feeAmount;

  return {
    grossAmount,
    feeAmount,
    feePercentage,
    netAmount,
  };
}

/**
 * Calculate fees when CUSTOMER PAYS FEE for incoming payments
 * 
 * @param baseAmount - The amount user wants to receive (e.g., 3500)
 * @param feePercentageValue - Fee percentage from database (60 = 6%) or undefined for default
 * @returns {baseAmount: 3500, feeAmount: 210, totalForProvider: 3710}
 * 
 * LOGIQUE FRAIS À LA CHARGE DU CLIENT:
 * - L'utilisateur crée un lien de 3500 XOF avec customerPaysFee=true
 * - Les frais sont calculés sur le montant de base: 3500 * X% = Y XOF
 * - Le client paie le TOTAL: 3500 + Y = Z XOF
 * - Le fournisseur reçoit Z XOF
 * - L'utilisateur reçoit le montant exact: 3500 XOF (sans déduction)
 * 
 * Usage:
 * - Send totalForProvider to payment provider
 * - Credit baseAmount to user balance
 * - Store baseAmount as the net amount in transaction
 */
export function calculateCustomerPaysFee(baseAmount: number, feePercentageValue?: number): {
  baseAmount: number;
  feeAmount: number;
  feePercentage: number;
  totalForProvider: number;
} {
  const feePercentage = getFeePercentage(feePercentageValue);
  const feeAmount = Math.floor((baseAmount * feePercentage) / 1000);
  const totalForProvider = baseAmount + feeAmount;

  return {
    baseAmount,
    feeAmount,
    feePercentage,
    totalForProvider,
  };
}

/**
 * Calculate fees for OUTGOING payments (withdrawals, transfers)
 * 
 * @param grossAmount - The GROSS amount user enters (e.g., 10000)
 * @param feePercentageValue - Fee percentage from database (60 = 6%) or undefined for default
 * @returns {grossAmount: 10000, feeAmount: 600, amountReceived: 9400, totalDeductedFromBalance: 10000}
 * 
 * LOGIQUE:
 * - L'utilisateur écrit 10000 XOF
 * - Les frais (e.g., 6% = 600) sont soustraits du montant écrit
 * - L'utilisateur reçoit 9400 XOF
 * - Le solde est débité de 10000 XOF (pas 10600)
 * 
 * Usage:
 * - Debit totalDeductedFromBalance from user balance (10000)
 * - Send amountReceived to provider (9400)
 * - Store grossAmount in transaction.amount (10000)
 * - Display grossAmount in transaction history (10000)
 */
export function calculateOutgoingFee(grossAmount: number, feePercentageValue?: number | string): {
  grossAmount: number;
  feeAmount: number;
  feePercentage: number;
  amountReceived: number;
  totalDeductedFromBalance: number;
} {
  // Handle case where country string was passed instead of fee percentage (legacy calls)
  const feePercentage = typeof feePercentageValue === 'string' 
    ? DEFAULT_FEE_PERCENTAGE 
    : getFeePercentage(feePercentageValue);
  const feeAmount = Math.floor((grossAmount * feePercentage) / 1000);
  const amountReceived = grossAmount - feeAmount;
  const totalDeductedFromBalance = grossAmount;

  return {
    grossAmount,
    feeAmount,
    feePercentage,
    amountReceived,
    totalDeductedFromBalance,
  };
}

