                    </div>
                  )}
                  {mbiyoOtpInfo.hint && (
                    <p className="mt-1 text-xs text-orange-600 dark:text-orange-400">{mbiyoOtpInfo.hint}</p>
                  )}
                </>
              ) : (
                <>
                  <div className="mt-2 flex items-center gap-2">
                    <div className="flex-1 bg-white dark:bg-gray-900 border border-orange-300 dark:border-orange-700 rounded-md px-3 py-2">
                      <code className="text-base font-bold text-orange-700 dark:text-orange-400">
                        {getOrangeUssdCode(country)}
                      </code>
                    </div>
                    <Button
                      type="button"
                      variant="outline"
                      size="sm"
                      onClick={() => copyUssdCode(getOrangeUssdCode(country))}
                      className="border-orange-300 hover:bg-orange-100 dark:hover:bg-orange-900"
                      data-testid="button-copy-ussd-form"
                    >
                      {copiedUssd ? <Check className="h-4 w-4 text-green-600" /> : <Copy className="h-4 w-4" />}
                    </Button>
                  </div>
                  <p className="mt-2 text-xs text-orange-700 dark:text-orange-400">
                    {getOrangeUssdHint(country)}
                  </p>
                </>
              )}
            </AlertDescription>
          </Alert>

          <div className="space-y-2">
            <Label>Code OTP</Label>
            <Input
              placeholder="Entrez le code obtenu"
              value={isMbiyoOtpOperator ? mbiyoOtpCode : authCode}
              onChange={(e) => isMbiyoOtpOperator ? setMbiyoOtpCode(e.target.value) : setAuthCode(e.target.value)}
              data-testid="input-otp-form"
            />
            <p className="text-xs text-muted-foreground">
              Composez le code USSD ci-dessus, puis entrez le code de paiement obtenu
            </p>
          </div>
        </div>
      )}

      {conversionData && (
        <div className="bg-green-50 dark:bg-green-950 p-3 rounded-md border border-green-200 dark:border-green-800">
          <p className="text-sm text-green-700 dark:text-green-300 font-medium">
            Montant à payer
          </p>
          {conversionData.isLoading ? (
            <div className="flex items-center gap-2 mt-1">
              <Loader2 className="h-4 w-4 animate-spin text-green-600" />
              <span className="text-sm text-green-600">Conversion en cours...</span>
            </div>
          ) : (
            <p className="text-lg font-bold text-green-800 dark:text-green-200" data-testid="text-converted-amount">
              {new Intl.NumberFormat("fr-FR", {
                minimumFractionDigits: getCurrencyDecimals(conversionData.targetCurrency),
                maximumFractionDigits: getCurrencyDecimals(conversionData.targetCurrency),
              }).format(conversionData.convertedAmount)} {conversionData.targetCurrency}
            </p>
          )}
        </div>
      )}

      <Button
        onClick={handleSubmit}
        disabled={initMutation.isPending || noOperatorsAvailable || (Boolean(showOtpOnForm) && !(isMbiyoOtpOperator ? mbiyoOtpCode.trim() : authCode.trim()))}
        className="w-full"
        size="lg"
        data-testid="button-submit-payment"
      >
        {initMutation.isPending ? (
          <>
            <Loader2 className="w-4 h-4 mr-2 animate-spin" />
            Traitement...
          </>
        ) : (
          `Payer ${displayAmount.toLocaleString()} ${ownerCurrency}`
        )}
      </Button>
    </div>
  );

  return (
    <div className="w-full min-h-screen flex items-center justify-center bg-gradient-to-br from-primary/5 via-background to-accent/5 p-4">
      <Card className="w-full max-w-md">
        <CardHeader className="space-y-2">
          <div className="flex items-center gap-2 mb-2">
            <Link href="/">
              <img src={logoImage} alt="BKApay" className="w-10 h-10 rounded-lg cursor-pointer" />
            </Link>
            <Link href="/" className="font-bold text-lg text-primary hover:underline">
              BKApay
            </Link>
          </div>
          <CardTitle>Payer a {apiKeyInfo.siteName}</CardTitle>
        </CardHeader>

        <CardContent className="space-y-6">
          <div className="space-y-3 pb-4 border-b">
            <div>
              <p className="text-sm text-muted-foreground mb-1">Montant a payer</p>
              <p className="text-3xl font-bold text-primary">
                {displayAmount.toLocaleString()} <span className="text-lg">{ownerCurrency}</span>
              </p>
              {apiKeyInfo?.customerPaysFee && hasOperatorSelected && dynamicFee && (
                <p className="text-xs text-muted-foreground">
                  (Frais de {(dynamicFee.feePercentage / 10).toFixed(1)}% inclus: {dynamicFee.feeAmount.toLocaleString()} {ownerCurrency})
                </p>
              )}
              {apiKeyInfo?.customerPaysFee && !hasOperatorSelected && (
                <p className="text-xs text-muted-foreground">
                  (Selectionnez un pays et operateur pour voir les frais)
                </p>
              )}
            </div>
            <div>
              <p className="text-sm text-muted-foreground">Completez votre paiement en remplissant les informations</p>
              {description && (
                <p className="text-sm text-foreground mt-1">{description}</p>
              )}
            </div>
          </div>

          <PaymentMethodSelector
            defaultMethod={(() => {
              try {
                const cryptoKey = `bkapay_crypto_${key}`;
                const saved = localStorage.getItem(cryptoKey);
                if (saved) {
                  const data = JSON.parse(saved);
                  if (data.paymentDetails && data.createdAt) {
                    const elapsed = Math.floor((Date.now() - data.createdAt) / 1000);
                    if ((data.expiresIn || 1800) - elapsed > 0) return "crypto";
                  }
                }
              } catch {}
              return "mobile_money";
            })()}
            mobileMoneyContent={mobileMoneyForm}
            cryptoContent={
              amount && amount >= 500 ? (
                <CryptoPaymentFlow
                  amount={amount}
                  currency={ownerCurrency}
                  apiKeyId={key}
                  customerPaysFee={(apiKeyInfo as any)?.customerPaysCryptoFee || false}
                  orderDescription={description || `Paiement à ${apiKeyInfo?.siteName}`}
                  customerName={customerName}
                  customerEmail={customerEmail}
                  customerPhone={customerPhone}
                  onSuccess={() => {
                    setPaymentStage("completed");
                    if (key) clearPaymentState(key);
                    toast({
                      title: "Paiement reussi",
                      description: "Votre transaction crypto a ete confirmee",
                    });
                    if (isInlineMode && window.parent !== window) {
                      setTimeout(() => {
                        window.parent.postMessage({
                          type: "bkapay_payment_success",
                          transactionId,
                          amount,
                          status: "completed",
                        }, "*");
                      }, 3000);
                    } else if (callbackUrl) {
                      setTimeout(() => {
                        window.location.href = `${callbackUrl}${callbackUrl.includes('?') ? '&' : '?'}status=success&amount=${amount}`;
                      }, 2000);
                    }
                  }}
                />
              ) : (
                <div className="p-4 text-center text-muted-foreground">
                  Le montant minimum pour payer en crypto est de 500 {ownerCurrency}
                </div>
              )
            }
          />

          <div className="text-center pt-4 border-t">
            <Link href="/" className="text-xs text-primary hover:underline cursor-pointer">
              Paiement securise par BKApay
            </Link>
          </div>
        </CardContent>
      </Card>
    </div>
  );
}

client/src/pages/documentation-version.t.content:
import { Card, CardContent, CardHeader, CardTitle } from "@/components/ui/card";
import { ExternalLink, AlertTriangle, ArrowRight, Clock, Monitor } from "lucide-react";
import { Button } from "@/components/ui/button";
import { Badge } from "@/components/ui/badge";
import { Alert, AlertDescription, AlertTitle } from "@/components/ui/alert";
import { useLocation } from "wouter";
import { 
  DOC_VERSIONS, 
  CURRENT_VERSION, 
  getDocVersion, 
  getLatestVersion,
  type DocVersion 
} from "@/lib/doc-versions";

interface DocumentationVersionProps {
  version: string;
}

function DeprecatedBanner({ version, latestVersion }: { version: DocVersion; latestVersion: DocVersion }) {
  const [, setLocation] = useLocation();

  return (
    <Alert className="mb-6 border-amber-500/50 bg-amber-500/10">
      <AlertTriangle className="h-4 w-4 text-amber-500" />
      <AlertTitle className="text-amber-600 dark:text-amber-400">Version obsolete</AlertTitle>
      <AlertDescription className="space-y-3">
        <p className="text-sm">
          Cette version de la documentation ({version.version}) est obsolete depuis le {version.releaseDate}.
          Veuillez utiliser la derniere version pour beneficier des dernieres fonctionnalites.
        </p>
        <Button 
          onClick={() => setLocation(`/documentation/${latestVersion.version}`)}
          size="sm"
          className="gap-2"
          data-testid="button-go-latest"
        >
          Voir la version {latestVersion.version}
          <ArrowRight className="w-4 h-4" />
        </Button>
      </AlertDescription>
    </Alert>
  );
}

function VersionNotFound({ requestedVersion }: { requestedVersion: string }) {
  const [, setLocation] = useLocation();
  const latestVersion = getLatestVersion();

  return (
    <div className="max-w-2xl mx-auto py-12">
      <Card className="border-destructive/50">
        <CardHeader className="text-center">
          <div className="mx-auto w-16 h-16 rounded-full bg-destructive/10 flex items-center justify-center mb-4">
            <AlertTriangle className="w-8 h-8 text-destructive" />
          </div>
          <CardTitle className="text-2xl">Version introuvable</CardTitle>
        </CardHeader>
        <CardContent className="space-y-6 text-center">
          <p className="text-muted-foreground">
            La version <span className="font-mono font-bold text-foreground">{requestedVersion}</span> de la documentation n'existe pas ou n'est plus disponible.
          </p>

          <div className="bg-muted/50 rounded-lg p-4">
            <p className="text-sm text-muted-foreground mb-3">Versions disponibles:</p>
            <div className="flex flex-wrap justify-center gap-2">
              {DOC_VERSIONS.filter(v => !v.isDeprecated).map(v => (
                <Badge 
                  key={v.version}
                  variant={v.isLatest ? "default" : "secondary"}
                  className="cursor-pointer"
                  onClick={() => setLocation(`/documentation/${v.version}`)}
                  data-testid={`badge-version-${v.version}`}
                >
                  {v.version}
                  {v.isLatest && " (Actuelle)"}
                </Badge>
              ))}
            </div>
          </div>

          <Button 
            onClick={() => setLocation(`/documentation/${latestVersion.version}`)}
            size="lg"
            className="gap-2"
            data-testid="button-go-latest-from-404"
          >
            Voir la documentation actuelle ({latestVersion.version})
            <ArrowRight className="w-4 h-4" />
          </Button>
        </CardContent>
      </Card>
    </div>
  );
}

function VersionSelector({ currentVersion }: { currentVersion: string }) {
  const [, setLocation] = useLocation();

  return (
    <div className="flex items-center gap-2 flex-wrap">
      <span className="text-sm text-muted-foreground">Version:</span>
      {DOC_VERSIONS.map(v => (
        <Badge 
          key={v.version}
          variant={v.version === currentVersion ? "default" : "outline"}
          className={`cursor-pointer ${v.isDeprecated ? "opacity-60" : ""}`}
          onClick={() => setLocation(`/documentation/${v.version}`)}
          data-testid={`select-version-${v.version}`}
        >
          {v.version}
          {v.isLatest && " (Actuelle)"}
          {v.isDeprecated && " (Obsolete)"}
        </Badge>
      ))}
    </div>
  );
}

function Changelog({ version }: { version: DocVersion }) {
  if (!version.changelog || version.changelog.length === 0) return null;

  return (
    <Card className="mb-6 border-primary/20">
      <CardHeader className="pb-3">
        <CardTitle className="flex items-center gap-2 text-lg">
          <Clock className="w-5 h-5" />
          Nouveautes de la version {version.version}
        </CardTitle>
      </CardHeader>
      <CardContent>
        <ul className="space-y-2">
          {version.changelog.map((item, index) => (
            <li key={index} className="flex items-start gap-2 text-sm">
              <span className="text-primary mt-1">•</span>
              <span className="text-muted-foreground">{item}</span>
            </li>
          ))}
        </ul>
        <p className="text-xs text-muted-foreground mt-4">
          Publiee le {version.releaseDate}
        </p>
      </CardContent>
    </Card>
  );
}

export default function DocumentationVersion({ version }: DocumentationVersionProps) {
  const [location, setLocation] = useLocation();
  const basePath = location.startsWith("/dashboard") ? "/dashboard/documentation" : "/documentation";

  const docVersion = getDocVersion(version);
  const latestVersion = getLatestVersion();

  if (!docVersion) {
    return <VersionNotFound requestedVersion={version} />;
  }

  return (
    <div className="space-y-6 max-w-4xl mx-auto px-4 py-8">
      <div className="mb-8">
        <div className="flex flex-col sm:flex-row sm:items-center sm:justify-between gap-4 mb-4">
          <h1 className="text-3xl font-bold text-foreground" data-testid="text-doc-title">
            Documentation API BKApay
          </h1>
          <Badge variant="secondary" className="w-fit text-sm" data-testid="badge-current-version">
            {docVersion.version}
          </Badge>
        </div>
        <p className="text-sm text-muted-foreground mb-4">
          Integrez facilement les paiements mobile money dans votre application
        </p>
        <VersionSelector currentVersion={docVersion.version} />
      </div>

      {docVersion.isDeprecated && (
        <DeprecatedBanner version={docVersion} latestVersion={latestVersion} />
      )}

      {docVersion.isLatest && <Changelog version={docVersion} />}

      <div className="space-y-4">
        <h2 className="text-xl font-semibold text-foreground">Choisissez votre type d'integration</h2>
        <p className="text-sm text-muted-foreground">
          BKApay propose deux methodes d'integration. Cliquez sur celle qui convient a votre projet.
        </p>
      </div>

      <div className="grid grid-cols-1 md:grid-cols-2 gap-4">
        <Card 
          className="cursor-pointer hover-elevate transition-colors border-2 border-border"
          onClick={() => setLocation(`${basePath}/redirect/${docVersion.version}`)}
          data-testid="card-redirect-checkout"
        >
          <CardHeader>
            <div className="w-12 h-12 rounded-lg bg-primary/10 flex items-center justify-center mb-3">
              <ExternalLink className="w-6 h-6 text-primary" />
            </div>
            <CardTitle className="text-lg">Redirect Checkout / HPP</CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <p className="text-sm text-muted-foreground">
              Le client est redirige vers la page de paiement securisee BKApay. 
              Ideal pour une integration rapide sans code complexe.
            </p>
            <ul className="space-y-2 text-sm text-muted-foreground">
              <li className="flex items-start gap-2">
                <span className="text-primary mt-0.5">•</span>
                Integration en quelques lignes de code
              </li>
              <li className="flex items-start gap-2">
                <span className="text-primary mt-0.5">•</span>
                Aucun code JavaScript requis
              </li>
              <li className="flex items-start gap-2">
                <span className="text-primary mt-0.5">•</span>
                Retour automatique sur votre site apres paiement
              </li>
            </ul>
            <Button className="w-full gap-2" data-testid="button-go-redirect">
              Voir la documentation
              <ArrowRight className="w-4 h-4" />
            </Button>
          </CardContent>
        </Card>

        <Card 
          className="cursor-pointer hover-elevate transition-colors border-2 border-border"
          onClick={() => setLocation(`${basePath}/inline/${docVersion.version}`)}
          data-testid="card-inline-checkout"
        >
          <CardHeader>
            <div className="w-12 h-12 rounded-lg bg-primary/10 flex items-center justify-center mb-3">
              <Monitor className="w-6 h-6 text-primary" />
            </div>
            <CardTitle className="text-lg">Inline / Modal Checkout</CardTitle>
          </CardHeader>
          <CardContent className="space-y-4">
            <p className="text-sm text-muted-foreground">
              La fenetre de paiement s'ouvre directement sur votre site via une modal.
              Le client ne quitte jamais votre page.
            </p>
            <ul className="space-y-2 text-sm text-muted-foreground">
              <li className="flex items-start gap-2">
                <span className="text-primary mt-0.5">•</span>
                Experience de paiement fluide
              </li>
              <li className="flex items-start gap-2">
                <span className="text-primary mt-0.5">•</span>
                Callbacks JavaScript (onSuccess, onError)
              </li>
              <li className="flex items-start gap-2">
                <span className="text-primary mt-0.5">•</span>
                Compatible web et mobile (React Native, Flutter)
              </li>
            </ul>
            <Button className="w-full gap-2" data-testid="button-go-inline">
              Voir la documentation
              <ArrowRight className="w-4 h-4" />
            </Button>
          </CardContent>
        </Card>
      </div>

      <div className="text-center py-8 border-t">
        <p className="text-sm text-muted-foreground">
          Documentation API BKApay - Version {docVersion.version}
        </p>
        <p className="text-xs text-muted-foreground mt-1">
          Derniere mise a jour: {docVersion.releaseDate}
        </p>
      </div>
    </div>
  );
}

client/src/lib/doc-versions.ts.content:
export interface DocVersion {
  version: string;
  releaseDate: string;
  isLatest: boolean;
  isDeprecated: boolean;
  changelog?: string[];
}

export const CURRENT_VERSION = "v1.4";

export const DOC_VERSIONS: DocVersion[] = [
  {
    version: "v1.4",
    releaseDate: "2026-02-09",
    isLatest: true,
    isDeprecated: false,
    changelog: [
      "Integration Inline/Modal Checkout sans redirection",
      "SDK JavaScript BKApay pour integration iframe",
      "Documentation separee par type d'integration (Redirect et Inline)",
      "Exemples de code React, PHP, Python et Mobile",
      "Amelioration de la securite postMessage"
    ]
  },
  {
    version: "v1.3",
    releaseDate: "2025-12-06",
    isLatest: false,
    isDeprecated: false,
    changelog: [
      "Webhooks pour activation automatique d'abonnements",
      "Notifications POST signees HMAC-SHA256",
      "Configuration du callback URL dans le dashboard",
      "Exemples de code Node.js et PHP pour webhooks"
    ]
  },
  {
    version: "v1.2",
    releaseDate: "2025-11-26",
    isLatest: false,
    isDeprecated: true,
    changelog: [
      "Ajout du parametre callback pour les redirections",
      "Montant minimum de 100 XOF",
      "Recherche de transactions par client",
      "Amelioration des messages d'erreur"
    ]
  },
  {
    version: "v1.1",
    releaseDate: "2025-11-15",
    isLatest: false,
    isDeprecated: true,
    changelog: [
      "Support des 19 operateurs SOFTPAY",
      "Integration Orange Money OTP",
      "Flux Wave avec redirection"
    ]
  },
  {
    version: "v1.0",
    releaseDate: "2025-11-01",
    isLatest: false,
    isDeprecated: true,
    changelog: [
      "Version initiale de l'API",
      "Support des paiements mobile money",
      "Tableau de bord marchand"
    ]
  }
];

export function getDocVersion(version: string): DocVersion | undefined {
  return DOC_VERSIONS.find(v => v.version.toLowerCase() === version.toLowerCase());
}

export function getLatestVersion(): DocVersion {
  return DOC_VERSIONS.find(v => v.isLatest) || DOC_VERSIONS[0];
}

export function isValidVersion(version: string): boolean {
  return DOC_VERSIONS.some(v => v.version.toLowerCase() === version.toLowerCase());
}

