                </div>
              </div>
            ))}
          </div>

          {(!currencies || currencies.length === 0) && (
            <div className="text-center py-8 text-muted-foreground">
              Aucune cryptomonnaie configurée. Activez NOWPayments dans la page Fournisseurs.
            </div>
          )}
        </CardContent>
      </Card>
    </div>
  );
}

