const COUNTRY_DATA: Record<string, { name: string }> = {
  BJ: { name: "Benin" },
  TG: { name: "Togo" },
  CI: { name: "Cote d'Ivoire" },
  SN: { name: "Senegal" },
  BF: { name: "Burkina Faso" },
